//! TikTok-ready post caption generation.
//!
//! Strict multi-mode system: 5 independent modes × GameType style.
//! Each caption is generated by: `generate_caption(event_summary, mode, game_type)`.
//!
//! Modes: DirectQuote, InternalThought, Blame, Observation, Minimal.
//! GameTypes: FPS, Horror, Cozy, Social, Generic.
//!
//! Every caption references what happened.  No fabricated outcomes, no clickbait.

use crate::pipeline::CandidateClip;
use crate::error::AppError;
use crate::detection::Platform;
use once_cell::sync::Lazy;

// ═══════════════════════════════════════════════════════════════════
//  Output
// ═══════════════════════════════════════════════════════════════════

/// One caption per mode, labeled by mode name.
#[derive(Debug, Clone, serde::Serialize, serde::Deserialize)]
pub struct PostCaptions {
    /// All generated captions, one per mode.
    pub captions: Vec<CaptionVariant>,
    pub hashtags: Vec<String>,
    /// Which system generated these: "free" or "llm".
    #[serde(default = "default_source")]
    pub source: String,

    // Legacy fields — populated from the first 3 captions for backward compat.
    pub casual: String,
    pub funny: String,
    pub hype: String,
}

fn default_source() -> String { "free".into() }

#[derive(Debug, Clone, serde::Serialize, serde::Deserialize)]
pub struct CaptionVariant {
    /// Which mode generated this caption.
    pub mode: String,
    /// Human-readable mode label for the UI.
    pub label: String,
    /// The caption text.
    pub text: String,
}

// ═══════════════════════════════════════════════════════════════════
//  GameType detection
// ═══════════════════════════════════════════════════════════════════

/// Game type — determines wording style, phrasing patterns, and
/// blame targets across every caption mode.
///
/// | GameType | Style               | Vocab                          |
/// |----------|---------------------|--------------------------------|
/// | FPS      | Competitive, fast   | "pushed", "dropped", "one-tap" |
/// | Horror   | Dread, survival     | "the dark", "behind me"        |
/// | Cozy     | Chaotic, wholesome  | "whoops", "the kitchen"        |
/// | Social   | Group dynamics      | "the team", "whose fault"      |
/// | Generic  | Neutral streamer    | plain, no genre flavor         |
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum GameType {
    /// FPS, battle royale, competitive PvP.
    FPS,
    /// Horror, jumpscare-heavy, survival horror.
    Horror,
    /// Cozy games, cooking sims, chaotic physics games.
    Cozy,
    /// Party games, social deduction, co-op chaos.
    Social,
    /// Anything that doesn't clearly fit above.
    Generic,
}

/// Backward-compat alias — existing code that references `Tone` still compiles.
pub type Tone = GameType;

/// Detect game type from tags, transcript, and signal scores.
///
/// Checks (in priority order):
///   1. Tags that strongly indicate a genre
///   2. Transcript style (genre-specific vocabulary)
///   3. Signal mix (audio-heavy = action, speech-heavy = social)
pub fn detect_game_type(
    tags: &[String],
    transcript: Option<&str>,
    audio_score: f64,
    speech_score: f64,
    scene_score: f64,
) -> GameType {
    let has = |t: &str| tags.iter().any(|x| x.to_lowercase().contains(t));

    // ── Tag-based (strongest signal) ──

    // Horror indicators
    if has("jumpscare") || has("scare") {
        return GameType::Horror;
    }
    if has("ambush") && has("panic") && !has("fight") {
        return GameType::Horror;
    }

    // FPS/action indicators
    if has("fight") || has("kill") || has("headshot") || has("snipe") {
        return GameType::FPS;
    }
    if has("ambush") && has("fight") {
        return GameType::FPS;
    }

    // Cozy/funny indicators
    if has("crash") || has("explosion") && has("celebration") {
        return GameType::Cozy;
    }

    // Social indicators
    if has("reaction") && has("hype") && speech_score > audio_score {
        return GameType::Social;
    }

    // ── Transcript-based ──
    if let Some(text) = transcript {
        let lower = text.to_lowercase();
        if lower.contains("scared") || lower.contains("terrified")
            || lower.contains("behind you") || lower.contains("dont look")
        {
            return GameType::Horror;
        }
        if lower.contains("whose fault") || lower.contains("blame")
            || lower.contains("you did this") || lower.contains("team")
            || lower.contains("why did you") || lower.contains("together")
        {
            return GameType::Social;
        }
        if lower.contains("kitchen") || lower.contains("recipe")
            || lower.contains("oops") || lower.contains("whoops")
            || lower.contains("mess") || lower.contains("broke")
        {
            return GameType::Cozy;
        }
    }

    // ── Signal mix ──
    if audio_score > 0.7 && scene_score > 0.5 && speech_score < 0.4 {
        return GameType::FPS;
    }
    if speech_score > 0.6 && audio_score < 0.5 {
        return GameType::Social;
    }

    GameType::Generic
}

/// Backward-compat wrapper — calls `detect_game_type`.
fn classify_tone(
    tags: &[String], transcript: Option<&str>,
    audio_score: f64, speech_score: f64, scene_score: f64,
) -> GameType {
    detect_game_type(tags, transcript, audio_score, speech_score, scene_score)
}

impl GameType {
    /// Human-readable label for the LLM prompt.
    pub fn label(self) -> &'static str {
        match self {
            GameType::FPS     => "FPS / competitive shooter",
            GameType::Horror  => "horror / survival",
            GameType::Cozy    => "cozy / chaotic casual",
            GameType::Social  => "social / party / co-op",
            GameType::Generic => "general gaming",
        }
    }
}

// ═══════════════════════════════════════════════════════════════════
//  Event summary — public preprocessing step
// ═══════════════════════════════════════════════════════════════════
//
//  Generates a 1-sentence description of what happened in the clip.
//  This is the foundation that all captions are built on.
//
//  Priority:
//    1. Transcript action + tag context  ("missed the shot during the fight")
//    2. Compound tag synthesis           ("got ambushed and panicked")
//    3. Single event + tone              ("something came out of the dark")
//    4. Tone-only fallback               ("got outplayed")

/// Generate a 1-sentence event summary from all available clip signals.
///
/// This is the preprocessing step that caption generation depends on.
/// The summary describes WHAT HAPPENED — not the reaction, not the vibe.
///
/// # Examples
///
/// | Transcript             | Tags                | Output                                   |
/// |------------------------|---------------------|------------------------------------------|
/// | "I missed that shot"   | fight, frustration  | "missed the shot and lost the fight"     |
/// | "oh god no"            | ambush, panic       | "got ambushed and completely panicked"   |
/// | (none)                 | fight, celebration  | "won the fight barely"                   |
/// | "what just happened"   | shock               | "something unexpected happened"          |
pub fn generate_event_summary(clip: &CandidateClip) -> String {
    let event = primary_event(&clip.tags);
    let tone = classify_tone(
        &clip.tags,
        clip.transcript_excerpt.as_deref(),
        clip.score_breakdown.audio_score,
        clip.score_breakdown.speech_score,
        clip.score_breakdown.scene_score,
    );
    let seed = clip.start_time as usize;

    // 1. Try transcript-enhanced summary
    if let Some(summary) = transcript_action_summary(
        clip.transcript_excerpt.as_deref(),
        event,
        &clip.tags,
        tone,
    ) {
        return summary;
    }

    // 2. Fall back to tag-based synthesis
    synthesize_event(event, tone, &clip.tags, seed)
}

/// Extract action-level intent from the transcript and combine with event context.
///
/// Returns None if the transcript is just filler/exclamations with no
/// recoverable action (e.g. "oh no", "what the hell").
fn transcript_action_summary(
    transcript: Option<&str>,
    event: Option<&str>,
    tags: &[String],
    _tone: Tone,
) -> Option<String> {
    let text = transcript?;
    let lower = text.to_lowercase();
    let words: Vec<&str> = lower.split_whitespace().collect();
    if words.len() < 3 { return None; }

    // Match action keywords that describe what happened (not reactions).
    // These are verbs/phrases a streamer says that reveal the actual event.
    let action = match () {
        _ if lower.contains("missed") && lower.contains("shot")
            => Some("missed the shot"),
        _ if lower.contains("missed")
            => Some("missed the play"),
        _ if lower.contains("whiffed") || lower.contains("whiff")
            => Some("whiffed completely"),
        _ if lower.contains("choked")
            => Some("choked at the worst time"),
        _ if lower.contains("died") || lower.contains("i'm dead")
            => Some("died"),
        _ if lower.contains("killed") && lower.contains("me")
            => Some("got killed"),
        _ if lower.contains("got him") || lower.contains("got them")
            => Some("got the kill"),
        _ if lower.contains("killed him") || lower.contains("killed it")
            => Some("landed the kill"),
        _ if lower.contains("stuck") || lower.contains("trapped")
            => Some("got trapped"),
        _ if lower.contains("fell") || lower.contains("falling")
            => Some("fell"),
        _ if lower.contains("ran") || lower.contains("running") || lower.contains("run")
            => Some("had to run for it"),
        _ if lower.contains("lost")
            => Some("lost it"),
        _ if lower.contains("won") || lower.contains("clutch")
            => Some("clutched it"),
        _ if lower.contains("broke") || lower.contains("broken")
            => Some("everything broke"),
        _ if lower.contains("explod") || lower.contains("blew up") || lower.contains("blown")
            => Some("got blown up"),
        _ if lower.contains("scared") || lower.contains("terrif")
            => Some("got scared"),
        _ if lower.contains("jumped") && !lower.contains("jumped in")
            => Some("got jumpscared"),
        _ if lower.contains("behind") && (lower.contains("you") || lower.contains("me"))
            => Some("something was right behind them"),
        _ if lower.contains("hit") && lower.contains("me")
            => Some("got hit out of nowhere"),
        _ if lower.contains("lag") || lower.contains("froze")
            => Some("froze at the worst moment"),
        _ if lower.contains("messed up") || lower.contains("screwed")
            => Some("messed up bad"),
        _ if lower.contains("forgot")
            => Some("forgot what to do"),
        _ => None,
    };

    let action = action?;

    // Combine action with tag-based context
    let has = |t: &str| tags.iter().any(|x| x == t);

    let combined = match event {
        Some("fight") if has("frustration") =>
            format!("{} and lost the fight", action),
        Some("fight") if has("celebration") =>
            format!("{} but won the fight anyway", action),
        Some("fight") if has("panic") =>
            format!("{} and the fight went sideways", action),
        Some("fight") =>
            format!("{} during the fight", action),
        Some("ambush") | Some("jumpscare") =>
            format!("{} after getting ambushed", action),
        Some("panic") =>
            format!("{} and panicked", action),
        Some("frustration") =>
            format!("{} and lost it", action),
        Some("clutch") | Some("celebration") =>
            format!("{} but somehow survived", action),
        _ => action.to_string(),
    };

    Some(combined)
}

// ═══════════════════════════════════════════════════════════════════
//  Public API
// ═══════════════════════════════════════════════════════════════════

/// Generate captions for a pipeline clip (deterministic — used during analysis).
pub fn generate(clip: &CandidateClip) -> PostCaptions {
    generate_with_seed(clip, 0)
}

/// Generate captions with an explicit seed (different seed = different output).
pub fn generate_with_seed(clip: &CandidateClip, seed: u32) -> PostCaptions {
    let event = primary_event(&clip.tags);
    let tone = classify_tone(
        &clip.tags,
        clip.transcript_excerpt.as_deref(),
        clip.score_breakdown.audio_score,
        clip.score_breakdown.speech_score,
        clip.score_breakdown.scene_score,
    );
    let s = mix_seed(clip.start_time as usize, seed);

    // Use the clip's pre-computed event summary if available,
    // otherwise generate one inline.
    let event_summary = clip.event_summary.clone()
        .unwrap_or_else(|| generate_event_summary(clip));

    let ctx = CaptionCtx {
        event_summary,
        quote: strong_quote(clip.transcript_excerpt.as_deref()),
        game_type: tone,
        seed: s,
    };
    let hashtags = build_hashtags(&clip.tags, ctx.game_type);
    build_variants(ctx, hashtags)
}

pub fn generate_from_parts(
    tags: &[String],
    transcript: Option<&str>,
    _title: &str,
    start_time: f64,
    audio_score: f64,
    speech_score: f64,
    scene_score: f64,
    seed: u32,
) -> PostCaptions {
    let event = primary_event(tags);
    let tone = classify_tone(tags, transcript, audio_score, speech_score, scene_score);
    let s = mix_seed(start_time as usize, seed);

    // Try transcript-enhanced summary, fall back to tag-based
    let event_summary = transcript_action_summary(transcript, event, tags, tone)
        .unwrap_or_else(|| synthesize_event(event, tone, tags, s));

    let ctx = CaptionCtx {
        event_summary,
        quote: strong_quote(transcript),
        game_type: tone,
        seed: s,
    };
    let hashtags = build_hashtags(tags, ctx.game_type);
    build_variants(ctx, hashtags)
}

pub fn generate_all(clips: &mut [CandidateClip]) {
    for clip in clips.iter_mut() {
        let captions = generate(clip);
        clip.post_captions = Some(captions);
    }
}

// ═══════════════════════════════════════════════════════════════════
//  Strict multi-mode caption system
// ═══════════════════════════════════════════════════════════════════
//
//  Architecture:
//    for mode in [DirectQuote, InternalThought, Blame, Observation, Minimal]:
//        generate_caption(event_summary, mode)
//
//  Each mode is a standalone function that builds its output FROM
//  the event_summary.  No shared templates.  No pre-written phrase
//  pools.  Every caption names what happened.
//
//  Global rules:
//    - MUST reference event_summary (the event is the caption's core)
//    - No generic phrases ("this happened", "caught on stream")
//    - Short and natural (under 15 words)

/// Everything a mode needs to produce one caption.
///
/// Prompt structure per caption:
///   1. event_summary  — what happened (required core)
///   2. base rules     — must reference event, no generic phrases, short
///   3. mode rules     — DirectQuote/Blame/InternalThought/Observation/Minimal
///   4. game_type      — FPS/Horror/Cozy/Social/Generic style overlay
struct CaptionCtx {
    /// Required: what happened in the clip ("missed the shot and lost the fight").
    event_summary: String,
    /// Optional: cleaned transcript quote from the streamer.
    quote: Option<String>,
    /// Game type — determines wording style, phrasing, and blame targets.
    game_type: GameType,
    /// Deterministic seed for structural variety on reroll.
    seed: usize,
}

// ═══════════════════════════════════════════════════════════════════
//  Template matrix (Phase 12 Wave 3b)
// ═══════════════════════════════════════════════════════════════════
//
//  Embedded at compile time via `include_str!` from
//  `config/caption_templates.toml` at the repo root. Parsed once at
//  first use (Lazy) and cached for the process lifetime.
//
//  Used by `synthesize_event()` as a matrix-first lookup before the
//  hardcoded fallback rules fire. Uncovered (emotion, context) pairs
//  return None and fall through unchanged — zero regression risk for
//  cells not yet seeded.
//
//  Supported slot placeholders: `{time_est}`, `{kill_count}`. Broader
//  slots (game name, streamer, enemy, weapon) land with Phase 1
//  per-game configs per decision 4 of section 9 in PHASE12_PROMPT_DIFF.md.

#[derive(serde::Deserialize)]
struct TemplateFile {
    templates: Vec<TemplateEntry>,
}

#[derive(serde::Deserialize, Clone, Debug)]
struct TemplateEntry {
    emotion: String,
    context: String,
    text: String,
}

/// The caption template matrix, loaded once from the embedded TOML.
///
/// Parse failure at compile time via `expect()` — malformed TOML means
/// the developer catches it before shipping, not testers at runtime.
static CAPTION_TEMPLATES: Lazy<Vec<TemplateEntry>> = Lazy::new(|| {
    const TOML: &str = include_str!("../../config/caption_templates.toml");
    let file: TemplateFile = toml::from_str(TOML)
        .expect("config/caption_templates.toml must parse at compile time");
    file.templates
});

/// Map clip signals (GameType + tags) to a matrix emotion row.
/// Returns None for uncovered cases — caller should fall through.
fn infer_emotion(tone: Tone, tags: &[String]) -> Option<&'static str> {
    let has = |t: &str| tags.iter().any(|x| x == t);

    // Explicit tag signals win — they're the strongest cue.
    if has("panic") || has("jumpscare") {
        return Some("panic");
    }
    if has("shock") || has("disbelief") {
        return Some("shock");
    }
    if has("celebration") || has("hype") {
        return Some("hype");
    }
    if has("frustration") {
        return Some("rage");
    }
    if has("reaction") {
        return Some("funny");
    }

    // Fallback to GameType-based inference for clips with no strong tags.
    match tone {
        Tone::Horror  => Some("panic"),
        Tone::FPS     => Some("hype"),
        Tone::Social  => Some("funny"),
        Tone::Cozy    => Some("funny"),
        Tone::Generic => None, // no strong signal — fall through to hardcoded
    }
}

/// Map clip signals (event + tags) to a matrix context column.
/// Returns None for uncovered cases — caller should fall through.
fn infer_context(event: Option<&str>, tags: &[String]) -> Option<&'static str> {
    let has = |t: &str| tags.iter().any(|x| x == t);

    // Event-driven mapping for the common shapes.
    match event {
        Some("clutch") => return Some("clutch"),
        Some("explosion") => return Some("explosion"),
        Some("ambush") | Some("jumpscare") => return Some("death"),
        Some("frustration") => return Some("fail"),
        _ => {}
    }

    // Compound tag combinations override the weaker event mapping.
    if has("fight") && has("celebration") {
        return Some("ace");
    }
    if has("fight") && has("frustration") {
        return Some("fail");
    }
    if has("celebration") {
        return Some("clutch");
    }
    if has("shock") || has("disbelief") || has("reaction") {
        return Some("reaction");
    }
    if has("panic") {
        return Some("chase");
    }

    // Fight with no other signal → default to reaction (the "something happened" shape).
    if event == Some("fight") || has("fight") {
        return Some("reaction");
    }

    None
}

/// Replace `{time_est}` and `{kill_count}` placeholders in a template.
///
/// Wave 3b only supports two slots — both use defensible placeholder
/// values ("5" and "3") since we don't yet extract precise numbers from
/// the signal pipeline. Broader slot extraction lands in Phase 1.
fn fill_slots(template: &str) -> String {
    // Using .replace() twice is fine — allocations are ~equal to a single
    // pass and the code stays readable.
    template
        .replace("{time_est}", "5")
        .replace("{kill_count}", "3")
}

/// Try to pick a caption template from the matrix for this clip's
/// (emotion, context) cell. Returns None if either axis can't be inferred
/// or the cell has no templates — caller falls through to hardcoded rules.
fn try_matrix_template(
    event: Option<&str>,
    tone: Tone,
    tags: &[String],
    seed: usize,
) -> Option<String> {
    let emotion = infer_emotion(tone, tags)?;
    let context = infer_context(event, tags)?;

    // Collect matches — `TEMPLATE_MATCH_SCAN` is O(N) over ~50 entries,
    // trivial cost. No need for a pre-built hashmap.
    let matches: Vec<&TemplateEntry> = CAPTION_TEMPLATES
        .iter()
        .filter(|t| t.emotion == emotion && t.context == context)
        .collect();

    if matches.is_empty() {
        return None;
    }

    let picked = matches[seed % matches.len()];
    Some(fill_slots(&picked.text))
}

// ═══════════════════════════════════════════════════════════════════
//  Event synthesis: tags + tone + event → concrete action sentence
// ═══════════════════════════════════════════════════════════════════
//
//  This is the critical step that makes captions specific.
//  Instead of "chaos" or "timing", we produce:
//    "got ambushed and panicked"
//    "the kitchen caught fire"
//    "teammate sold the round"
//
//  Wave 3b inserted a matrix-first lookup before the hardcoded rules:
//  if (emotion, context) can be inferred AND the matrix has templates
//  for that cell, use the matrix. Otherwise fall through to the
//  original hardcoded logic untouched.

/// Build a concrete event summary from available signals.
/// Returns a short action phrase (no "i", no quotes — just what happened).
fn synthesize_event(
    event: Option<&str>,
    tone: Tone,
    tags: &[String],
    seed: usize,
) -> String {
    // Matrix-first (Phase 12 Wave 3b). Falls through to hardcoded rules
    // below if no matrix template matches.
    if let Some(from_matrix) = try_matrix_template(event, tone, tags, seed) {
        return from_matrix;
    }

    let has = |t: &str| tags.iter().any(|x| x == t);

    // ── Compound tag combinations → specific events ──
    if has("fight") && has("panic") {
        return pick(seed, &[
            "fight broke out and went wrong fast",
            "got into a fight and panicked",
            "the fight spiraled out of control",
        ]);
    }
    if has("fight") && has("celebration") {
        return pick(seed, &[
            "won the fight barely",
            "clutched the fight at the last second",
            "somehow survived that fight",
        ]);
    }
    if has("fight") && has("frustration") {
        return pick(seed, &[
            "lost that fight and it stung",
            "the fight went wrong and it hurt",
            "got outplayed in the fight",
        ]);
    }
    if (has("jumpscare") || has("ambush")) && has("panic") {
        return pick(seed, &[
            "got ambushed and completely panicked",
            "something appeared out of nowhere",
            "got jumped and had zero time to react",
        ]);
    }
    if (has("jumpscare") || has("ambush")) && has("shock") {
        return pick(seed, &[
            "got scared out of nowhere",
            "something jumped out at the worst time",
            "the jumpscare hit with no warning",
        ]);
    }

    // ── Single event + tone → specific actions ──
    if let Some(ev) = event {
        return match (ev, tone) {
            ("ambush", GameType::Horror)  => pick(seed, &[
                "something came out of the dark",
                "turned a corner and regretted it",
                "heard a noise and it was already too late",
            ]),
            ("ambush", _)             => pick(seed, &[
                "got rushed with no warning",
                "enemy appeared out of nowhere",
                "got caught completely off guard",
            ]),
            ("fight", GameType::FPS)  => pick(seed, &[
                "took a fight and got dropped instantly",
                "pushed and it went wrong immediately",
                "the gunfight lasted about one second",
            ]),
            ("fight", _)              => pick(seed, &[
                "a fight broke out suddenly",
                "things got heated fast",
                "the fight went sideways",
            ]),
            ("clutch", _)             => pick(seed, &[
                "barely survived at the last second",
                "pulled it off with almost nothing left",
                "clutched it when it looked impossible",
            ]),
            ("panic", GameType::Cozy)     => pick(seed, &[
                "the kitchen caught fire",
                "everything went wrong at once",
                "the whole plan fell apart instantly",
            ]),
            ("panic", GameType::Social)   => pick(seed, &[
                "the whole group panicked at once",
                "someone made a bad call and everyone suffered",
                "the team fell apart in seconds",
            ]),
            ("panic", _)              => pick(seed, &[
                "everything went wrong at the same time",
                "panic set in and nothing worked",
                "lost control of the situation completely",
            ]),
            ("frustration", _)        => pick(seed, &[
                "nothing went right",
                "missed the obvious play",
                "made the wrong call and paid for it",
            ]),
            ("shock" | "disbelief", _) => pick(seed, &[
                "something unexpected happened",
                "nobody saw that coming",
                "it came completely out of nowhere",
            ]),
            ("hype" | "reaction", _)   => pick(seed, &[
                "something big happened and the reaction was instant",
                "the moment hit and the energy shifted",
                "it happened and there was no holding back",
            ]),
            ("explosion", _)          => pick(seed, &[
                "everything blew up with no warning",
                "an explosion hit out of nowhere",
                "it all went up in flames instantly",
            ]),
            _ => pick(seed, &[
                "something happened that nobody expected",
                "the moment came out of nowhere",
            ]),
        };
    }

    // ── Tone-only fallback ──
    match tone {
        GameType::Horror  => pick(seed, &["something scary happened", "got scared"]),
        GameType::Cozy    => pick(seed, &["things went chaotic", "the plan fell apart"]),
        GameType::Social  => pick(seed, &["the group fell apart", "someone messed up"]),
        GameType::FPS => pick(seed, &["got outplayed", "the play went wrong"]),
        GameType::Generic => pick(seed, &["something happened", "a moment hit"]),
    }
}

fn pick(seed: usize, opts: &[&str]) -> String {
    opts[seed % opts.len()].to_string()
}

// ═══════════════════════════════════════════════════════════════════
//  Modes
// ═══════════════════════════════════════════════════════════════════

#[derive(Clone, Copy, PartialEq, Eq)]
enum Mode {
    /// Spoken reaction — raw words someone would say in this moment.
    DirectQuote,
    /// External fault assignment — frustrated, ironic, pointing fingers.
    Blame,
    /// First-person reflection — inner monologue, personal, after-the-fact.
    InternalThought,
    /// Third-person description — detached, dry, documentary.
    Observation,
    /// 1–3 word gut punch — extracted from the event itself.
    Minimal,
}

const MODES: [Mode; 5] = [
    Mode::DirectQuote, Mode::Blame, Mode::InternalThought,
    Mode::Observation, Mode::Minimal,
];

fn mix_seed(base: usize, seed: u32) -> usize {
    let s = base.wrapping_mul(2654435761).wrapping_add(seed as usize);
    s ^ (s >> 16)
}

// ═══════════════════════════════════════════════════════════════════
//  Caption dispatch
// ═══════════════════════════════════════════════════════════════════

/// Generate one caption for a specific mode.
///
/// `event_summary` is the required foundation — every output must
/// reference what happened.  Each mode applies a unique transformation.
fn generate_caption(mode: Mode, ctx: &CaptionCtx) -> String {
    let text = match mode {
        Mode::DirectQuote     => gen_direct_quote(ctx),
        Mode::Blame           => gen_blame(ctx),
        Mode::InternalThought => gen_internal_thought(ctx),
        Mode::Observation     => gen_observation(ctx),
        Mode::Minimal         => gen_minimal(ctx),
    };

    // Global rule: reject generics, retry once with shifted seed
    if is_generic(&text) || text.to_lowercase() == ctx.event_summary.to_lowercase() {
        let retry = CaptionCtx {
            seed: ctx.seed.wrapping_add(9973),
            event_summary: ctx.event_summary.clone(),
            quote: ctx.quote.clone(),
            game_type: ctx.game_type,
        };
        return match mode {
            Mode::DirectQuote     => gen_direct_quote(&retry),
            Mode::Blame           => gen_blame(&retry),
            Mode::InternalThought => gen_internal_thought(&retry),
            Mode::Observation     => gen_observation(&retry),
            Mode::Minimal         => gen_minimal(&retry),
        };
    }

    text
}

fn is_generic(text: &str) -> bool {
    let lower = text.to_lowercase();
    GENERIC_PHRASES.iter().any(|p| lower.contains(p))
}

// ═══════════════════════════════════════════════════════════════════
//  Mode: DirectQuote — spoken reaction
// ═══════════════════════════════════════════════════════════════════
//
//  What someone would literally say in this moment.
//  If transcript quote exists: use it verbatim — that IS the caption.
//  If not: construct a spoken exclamation from the event_summary.
//  No commentary, no framing, no "i said". Just the words.

fn gen_direct_quote(ctx: &CaptionCtx) -> String {
    // Real speech → the quote IS the caption
    if let Some(ref q) = ctx.quote {
        // Vary the framing on reroll using seed
        let framings = [
            format!("\"{}\"", q),
            format!("\"{}\" — live", q),
            format!("\"{}\" — on stream", q),
        ];
        return framings[ctx.seed % framings.len()].clone();
    }

    // No transcript — construct what someone would say.
    // GameType determines the spoken style: FPS players react differently
    // than horror players or cozy streamers.
    let ev = &ctx.event_summary;
    let core = first_n_words(ev, 5);

    match ctx.game_type {
        GameType::FPS    => {
            let opts = [format!("\"no shot— {}\"", core), format!("\"how did {}\"", core)];
            opts[ctx.seed % opts.len()].clone()
        }
        GameType::Horror => {
            let opts = [format!("\"oh god— {}\"", core), format!("\"nope— {}\"", core)];
            opts[ctx.seed % opts.len()].clone()
        }
        GameType::Cozy   => {
            let opts = [format!("\"wait how did {}\"", core), format!("\"why did {}\"", core)];
            opts[ctx.seed % opts.len()].clone()
        }
        GameType::Social => {
            let opts = [format!("\"who— {}\"", core), format!("\"okay so {}\"", core)];
            opts[ctx.seed % opts.len()].clone()
        }
        GameType::Generic => {
            let opts = [format!("\"i just {}\"", core), format!("\"wait— {}\"", core), format!("\"{}\"", core)];
            opts[ctx.seed % opts.len()].clone()
        }
    }
}

// ═══════════════════════════════════════════════════════════════════
//  Mode: InternalThought — first-person reflection
// ═══════════════════════════════════════════════════════════════════
//
//  Inner monologue. Always "i". Reflective, personal, after-the-fact.
//  The thought directly names what happened — it's not vague.
//  Never detached. Never third-person. Never generic.
//
//  Sentence built by wrapping event_summary in a reflective frame.
//  Tone determines the emotional color of the reflection.

fn gen_internal_thought(ctx: &CaptionCtx) -> String {
    let ev = &ctx.event_summary;

    // If there's a quote, contrast internal vs external state.
    // Keep leading words short — captions_are_short test asserts ≤16 words total,
    // and a mid-length transcript quote adds 8+ on its own.
    if let Some(ref q) = ctx.quote {
        let opts = [
            format!("inside: calm. out loud: \"{}\"", q),
            format!("wanted to say nothing. said: \"{}\"", q),
            format!("told myself i wouldn't. then: \"{}\"", q),
        ];
        return opts[ctx.seed % opts.len()].clone();
    }

    // Tone determines the reflective frame around the event
    match ctx.game_type {
        GameType::Horror  => {
            let opts = [format!("i'm still not over when {}", ev), format!("i can't stop thinking about when {}", ev)];
            opts[ctx.seed % opts.len()].clone()
        }
        GameType::Cozy    => {
            let opts = [format!("i genuinely did not expect {}", ev), format!("nobody prepared me for {}", ev)];
            opts[ctx.seed % opts.len()].clone()
        }
        GameType::Social  => {
            let opts = [format!("i should have seen it coming. {}", ev), format!("i trusted them. then {}", ev)];
            opts[ctx.seed % opts.len()].clone()
        }
        GameType::FPS => {
            let opts = [format!("i keep replaying it. {}", ev), format!("i still think about when {}", ev)];
            opts[ctx.seed % opts.len()].clone()
        }
        GameType::Generic => {
            let opts = [
                format!("i knew {} was going to happen and i still wasn't ready", ev),
                format!("part of me saw {} coming. the rest of me didn't care", ev),
            ];
            opts[ctx.seed % opts.len()].clone()
        }
    }
}

// ═══════════════════════════════════════════════════════════════════
//  Mode: Blame — external fault assignment
// ═══════════════════════════════════════════════════════════════════
//
//  Points fingers. Frustrated. Ironic.
//  Never "i" as subject — always blaming something external.
//  Structure: [event happened] + [fault assigned].
//  Tone determines who or what gets blamed.

fn gen_blame(ctx: &CaptionCtx) -> String {
    let ev = &ctx.event_summary;

    // Quote path: speech followed by blame
    if let Some(ref q) = ctx.quote {
        let opts = [
            format!("\"{}\" — and whose fault was that", q),
            format!("\"{}\" — blame the game not me", q),
            format!("\"{}\" — someone needs to answer for this", q),
        ];
        return opts[ctx.seed % opts.len()].clone();
    }

    // Tone determines the blame target — derived from the game type
    match ctx.game_type {
        GameType::Horror  => {
            let opts = [format!("{} and nobody warned me", ev), format!("{} — this game set me up", ev)];
            opts[ctx.seed % opts.len()].clone()
        }
        GameType::Cozy    => {
            let opts = [format!("{} and it was entirely preventable", ev), format!("{} — the game did this on purpose", ev)];
            opts[ctx.seed % opts.len()].clone()
        }
        GameType::Social  => {
            let opts = [format!("{} and i know exactly whose fault that was", ev), format!("{} — trusting teammates was the first mistake", ev)];
            opts[ctx.seed % opts.len()].clone()
        }
        GameType::FPS => {
            let opts = [format!("{} and that was not a fair fight", ev), format!("{} — explain how that's balanced", ev)];
            opts[ctx.seed % opts.len()].clone()
        }
        GameType::Generic => {
            let opts = [format!("{}. somebody explain how that's okay", ev), format!("{}. i need answers", ev)];
            opts[ctx.seed % opts.len()].clone()
        }
    }
}

// ═══════════════════════════════════════════════════════════════════
//  Mode: Observation — third-person, dry
// ═══════════════════════════════════════════════════════════════════
//
//  Outside observer describing what happened. Detached. Factual.
//  No "i". No personal pronouns. Documentary tone.
//  The event is stated as observable fact — not felt, not reacted to.
//
//  Sentence built by framing event_summary as a documentable moment.
//  Seed selects the framing structure.

fn gen_observation(ctx: &CaptionCtx) -> String {
    let ev = &ctx.event_summary;

    match ctx.game_type {
        GameType::FPS     => {
            let opts = [format!("the play where {}. watch it back", ev), format!("frame by frame: {}", ev)];
            opts[ctx.seed % opts.len()].clone()
        }
        GameType::Horror  => {
            let opts = [format!("you can hear the panic when {}", ev), format!("the moment {}", ev)];
            opts[ctx.seed % opts.len()].clone()
        }
        GameType::Cozy    => {
            let opts = [format!("total destruction: {}", ev), format!("a quiet stream until {}", ev)];
            opts[ctx.seed % opts.len()].clone()
        }
        GameType::Social  => {
            let opts = [format!("the group the moment {}: silence", ev), format!("everyone watched {} happen", ev)];
            opts[ctx.seed % opts.len()].clone()
        }
        GameType::Generic => {
            let opts = [
                format!("the exact moment {}", ev),
                format!("{}. that's the whole clip", ev),
                format!("{} — in real time", ev),
            ];
            opts[ctx.seed % opts.len()].clone()
        }
    }
}

// ═══════════════════════════════════════════════════════════════════
//  Mode: Minimal — 1–3 word gut reaction
// ═══════════════════════════════════════════════════════════════════
//
//  Maximum density. Period energy.
//  The word is extracted FROM the event_summary — not a generic
//  mood word.  "missed the shot" → "missed."  "got ambushed" → "ambushed."
//  Always names what happened, just in one word.

fn gen_minimal(ctx: &CaptionCtx) -> String {
    // Minimal = short but COMPLETE phrase (3-6 words) that references clip content.
    // Never a single word. Always makes sense on its own.

    // If we have transcript, extract a short meaningful fragment
    if let Some(ref q) = ctx.quote {
        let short = extract_short_phrase(q, ctx.seed);
        if short.split_whitespace().count() >= 2 {
            return short;
        }
    }

    // Fall back to event summary — take first 4-6 words
    let ev_short = first_n_words(&ctx.event_summary, 5);

    match ctx.game_type {
        GameType::FPS     => format!("{} — gone", ev_short),
        GameType::Horror  => format!("{} — nope", ev_short),
        GameType::Cozy    => format!("{} — whoops", ev_short),
        GameType::Social  => format!("{} — really", ev_short),
        GameType::Generic => ev_short,
    }
}

/// Extract a short phrase (3-6 words) from transcript text.
/// Tries to find a punchy sentence fragment rather than a single word.
fn extract_short_phrase(text: &str, seed: usize) -> String {
    // Split on sentence boundaries
    let sentences: Vec<&str> = text.split(|c: char| c == '.' || c == '!' || c == '?')
        .map(|s| s.trim())
        .filter(|s| {
            let wc = s.split_whitespace().count();
            wc >= 2 && wc <= 8
        })
        .collect();

    if !sentences.is_empty() {
        let picked = sentences[seed % sentences.len()];
        // If short enough, use as-is; otherwise take first 6 words
        let words: Vec<&str> = picked.split_whitespace().take(6).collect();
        return words.join(" ").to_lowercase();
    }

    // No good sentences — take 3-5 content words from the text
    let skip: &[&str] = &[
        "the", "a", "an", "and", "or", "but", "in", "on", "at", "to",
        "of", "for", "with", "from", "um", "uh", "like", "so", "just",
    ];
    let content_words: Vec<&str> = text.split_whitespace()
        .filter(|w| {
            let clean = w.trim_matches(|c: char| !c.is_alphabetic()).to_lowercase();
            clean.len() >= 2 && !skip.contains(&clean.as_str())
        })
        .take(4)
        .collect();

    if content_words.len() >= 2 {
        content_words.join(" ").to_lowercase()
    } else {
        first_n_words(text, 4).to_lowercase()
    }
}

/// Extract the most impactful single word from an event summary.
/// Skips articles, prepositions, and low-information verbs.
fn extract_punch_word(summary: &str) -> &str {
    const SKIP: &[&str] = &[
        "the", "a", "an", "and", "or", "but", "in", "on", "at", "to",
        "of", "for", "with", "from", "was", "were", "is", "are",
        "that", "this", "it", "got", "went", "had", "out", "up",
        "no", "not", "just", "when", "then", "so", "too",
    ];

    for word in summary.split_whitespace() {
        let clean = word.trim_matches(|c: char| !c.is_alphabetic());
        if clean.len() >= 3 && !SKIP.contains(&clean.to_lowercase().as_str()) {
            return clean;
        }
    }

    // Fallback: first word
    summary.split_whitespace().next().unwrap_or("gone")
}

/// First N words of a string.
fn first_n_words(s: &str, n: usize) -> String {
    s.split_whitespace().take(n).collect::<Vec<_>>().join(" ")
}

// ═══════════════════════════════════════════════════════════════════
//  Variant assembly
// ═══════════════════════════════════════════════════════════════════

fn build_variants(ctx: CaptionCtx, hashtags: Vec<String>) -> PostCaptions {
    // for mode in modes: generate_caption(event_summary, mode)
    // Each mode gets its own seed so outputs don't correlate.
    let captions: Vec<CaptionVariant> = MODES.iter().enumerate().map(|(i, &mode)| {
        let mode_ctx = CaptionCtx {
            seed: ctx.seed.wrapping_mul(i as usize + 7),
            event_summary: ctx.event_summary.clone(),
            quote: ctx.quote.clone(),
            game_type: ctx.game_type,
        };
        let text = generate_caption(mode, &mode_ctx);
        CaptionVariant {
            mode: match mode {
                Mode::DirectQuote     => "direct_quote",
                Mode::Blame           => "blame",
                Mode::InternalThought => "internal_thought",
                Mode::Observation     => "observation",
                Mode::Minimal         => "minimal",
            }.into(),
            label: match mode {
                Mode::DirectQuote     => "Direct Quote",
                Mode::Blame           => "Blame",
                Mode::InternalThought => "Inner Thought",
                Mode::Observation     => "Observation",
                Mode::Minimal         => "Minimal",
            }.into(),
            text,
        }
    }).collect();

    // Legacy compat: first 3 captions fill casual/funny/hype
    let casual = captions.first().map(|c| c.text.clone()).unwrap_or_default();
    let funny  = captions.get(1).map(|c| c.text.clone()).unwrap_or_default();
    let hype   = captions.get(2).map(|c| c.text.clone()).unwrap_or_default();

    PostCaptions { captions, hashtags, source: "free".into(), casual, funny, hype }
}

// ═══════════════════════════════════════════════════════════════════
//  Genericness rejection
// ═══════════════════════════════════════════════════════════════════

const GENERIC_PHRASES: &[&str] = &[
    "this happened",
    "something happened",
    "a moment hit",
    "can't believe this",
    "caught on stream",
    "stream moment",
    "this clip",
    "this is a clip",
    "gaming moment",
    "this was crazy",
    "that was wild",
    "just happened",
    "it happened",
    "this is insane",
    "watch this",
    "you need to see this",
    "moment of the day",
    "clip of the day",
];

// ═══════════════════════════════════════════════════════════════════
//  Quote extraction
// ═══════════════════════════════════════════════════════════════════

fn strong_quote(transcript: Option<&str>) -> Option<String> {
    let text = transcript?.trim();
    if text.len() < 3 { return None; }
    let filler = ["like", "so", "um", "uh", "okay", "ok", "well"];
    let words: Vec<&str> = text.split_whitespace()
        .skip_while(|w| filler.contains(&w.to_lowercase().as_str()))
        .collect();
    if words.len() < 2 { return None; }

    // Take up to 20 words but try to end at a sentence boundary
    let taken: Vec<&str> = words.iter().take(20).copied().collect();
    let joined = taken.join(" ").to_lowercase();

    // Try to cut at a sentence boundary (. ! ?) to avoid mid-sentence truncation
    if let Some(pos) = joined.rfind(|c: char| c == '.' || c == '!' || c == '?') {
        let sentence = joined[..=pos].trim().to_string();
        if sentence.len() >= 5 {
            return Some(sentence);
        }
    }

    // No sentence boundary found — use all taken words (up to 20)
    Some(joined)
}

fn primary_event(tags: &[String]) -> Option<&'static str> {
    let has = |t: &str| tags.iter().any(|x| x == t);
    if has("jumpscare") || has("ambush") { return Some("ambush"); }
    if has("fight")       { return Some("fight"); }
    if has("explosion")   { return Some("explosion"); }
    if has("celebration") { return Some("clutch"); }
    if has("panic")       { return Some("panic"); }
    if has("frustration") { return Some("frustration"); }
    if has("disbelief")   { return Some("disbelief"); }
    if has("shock")       { return Some("shock"); }
    if has("hype")        { return Some("hype"); }
    if has("reaction")    { return Some("reaction"); }
    None
}

// ═══════════════════════════════════════════════════════════════════
//  Hashtags — tone + platform + streamer niche
// ═══════════════════════════════════════════════════════════════════
//
//  Strategy: 3 evergreen (platform-specific) + 2 niche (game + content).
//  Per the Phase 12 decision (section 9 of docs/PHASE12_PROMPT_DIFF.md),
//  hashtags are never LLM-generated — this function is the single source
//  of truth.
//
//  Back-compat: the old signature `build_hashtags(tags, tone)` is preserved
//  as a thin wrapper that delegates to `build_hashtags_v2` with
//  `Platform::Generic`, empty niche tags, and no game name. Existing
//  callers produce the same tag list they did before Wave 1 for that
//  default case, modulo ordering and the new evergreen set.

/// Backward-compat shim: produce hashtags with no platform/niche context.
/// Preserved so existing call sites (generate_with_seed, generate_from_parts,
/// build_hashtags_pub) keep working without modification in Wave 1.
fn build_hashtags(tags: &[String], tone: Tone) -> Vec<String> {
    build_hashtags_v2(tags, tone, Platform::Generic, &[], None)
}

/// Expanded hashtag builder — platform-aware, niche-aware.
///
/// Returns up to 5 hashtags:
/// - **3 evergreen** (from `platform.evergreen_hashtags()`)
/// - **1 game/tone niche** — game name (snake-cased) if present, else tone tag
/// - **1 content niche** — clutch / fail / jumpscare / or first of `streamer_niche_tags`
///
/// All output is lowercase, strip-non-alphanumeric, deduped, capped at 5.
pub fn build_hashtags_v2(
    tags: &[String],
    tone: Tone,
    platform: Platform,
    streamer_niche_tags: &[String],
    game_name: Option<&str>,
) -> Vec<String> {
    let mut out: Vec<String> = platform
        .evergreen_hashtags()
        .iter()
        .map(|s| s.to_string())
        .collect();

    // Niche slot 1: game name if present, else tone tag.
    let tone_tag = match tone {
        GameType::Horror  => "horrorgaming",
        GameType::Cozy    => "cozygaming",
        GameType::Social  => "partygame",
        GameType::FPS     => "fps",
        GameType::Generic => "clips",
    };
    if let Some(game) = game_name.map(sanitize_hashtag).filter(|g| !g.is_empty()) {
        out.push(game);
    } else {
        out.push(tone_tag.to_string());
    }

    // Niche slot 2: content-specific signal tag or first streamer-niche tag.
    let has = |t: &str| tags.iter().any(|x| x == t);
    if has("jumpscare") || has("ambush") {
        out.push("jumpscare".into());
    } else if has("celebration") || has("hype") {
        out.push("clutch".into());
    } else if has("frustration") || has("panic") {
        out.push("fail".into());
    } else if let Some(niche) = streamer_niche_tags.first().map(|s| sanitize_hashtag(s)) {
        if !niche.is_empty() {
            out.push(niche);
        }
    }

    // If we have headroom and a streamer-niche tag not yet included, append it.
    if out.len() < 5 {
        for niche in streamer_niche_tags.iter().skip(1) {
            let clean = sanitize_hashtag(niche);
            if !clean.is_empty() && !out.contains(&clean) {
                out.push(clean);
                if out.len() >= 5 {
                    break;
                }
            }
        }
    }

    out.dedup();
    out.truncate(5);
    out
}

/// Sanitize a string into a hashtag-safe form: lowercase, alphanumeric only,
/// no spaces. Empty if the input has no alphanumeric characters.
fn sanitize_hashtag(raw: &str) -> String {
    raw.chars()
        .filter(|c| c.is_ascii_alphanumeric())
        .flat_map(|c| c.to_lowercase())
        .collect()
}

// ═══════════════════════════════════════════════════════════════════
//  Title candidate types (Phase 12 Wave 2)
// ═══════════════════════════════════════════════════════════════════
//
//  Consumed by `generate_llm_titles()` and by callers who want to
//  re-score with a different platform / history context via
//  `detection::ranker::score_title`.

/// One of six title patterns derived from analysis of ~180 high-engagement gaming
/// short-form titles (TenZ, OtzStreams, Jynxzi, Lilith Omen + broader discovery).
/// The earlier 4-pattern framework (StakeArrowOutcome / EmotionColonDetail / QuoteTwist
/// / NaturalVoice) was replaced after real-world data showed its shapes — arrow
/// separators in particular — appear in zero high-engagement real titles.
///
/// Priority order by prevalence in real data:
/// 1. QuietFlex (~25%) — 2–4 word understatement
/// 2. AftermathConfession (~20%) — first-person past-tense self-deprecation
/// 3. Observational (~15%) — third-person narration of someone else's moment
/// 4. TechCallout (~15%) — named mechanic or technique
/// 5. SpecificSuperlative (~15%) — "worst/fastest/most X ever" pinned to a named thing
/// 6. CuriosityQuestion (~10%) — specific unanswered question
#[derive(Debug, Clone, Copy, PartialEq, Eq, serde::Serialize, serde::Deserialize)]
#[serde(rename_all = "SCREAMING_SNAKE_CASE")]
pub enum TitlePattern {
    /// 2–4 word understatement. The clip does the work. E.g. `"actually clean"`.
    QuietFlex,
    /// First-person past-tense or resigned present. E.g. `"gonna sleep on the couch again"`.
    AftermathConfession,
    /// Third-person narration of a character/enemy/teammate. E.g. `"Meg learnt to fly"`.
    Observational,
    /// Named in-game mechanic or technique. E.g. `"don't blind Legion when he's vaulting"`.
    TechCallout,
    /// "worst/fastest/most X" pinned to a named mechanic. E.g. `"the WORST hex in DBD"`.
    SpecificSuperlative,
    /// Specific unanswered question the clip resolves. E.g. `"why has nobody left the bus?"`.
    CuriosityQuestion,
}

/// A single title candidate produced by `generate_llm_titles()`.
///
/// `score` is filled in by `detection::ranker::score_title` during generation;
/// callers can re-score with their own `RankerContext` if needed (e.g. a
/// different target platform or an updated streamer history).
#[derive(Debug, Clone, serde::Serialize, serde::Deserialize)]
pub struct TitleCandidate {
    pub text: String,
    pub pattern: TitlePattern,
    /// Ranker score 0.0–1.0. 0.0 = banlist hit, hard reject.
    #[serde(default)]
    pub score: f32,
}

// ═══════════════════════════════════════════════════════════════════
//  Caption candidate types (Phase 12 Wave 3a)
// ═══════════════════════════════════════════════════════════════════
//
//  Consumed by `generate_llm_caption()`. Each candidate is a two-part
//  caption: `hook_line` (first ~50 chars, scroll-stopper) + `body` (rest).
//  Hashtags are NOT part of this struct — they come from the client-side
//  `build_hashtags_v2()` function per the Wave 1 decision 4.

/// A single caption candidate produced by `generate_llm_caption()`.
#[derive(Debug, Clone, serde::Serialize, serde::Deserialize)]
pub struct CaptionCandidate {
    /// Scroll-stopper — aim for ≤50 chars, client-side truncated if longer.
    /// Scored by `detection::ranker::score_title` (the ranker is title-shaped
    /// but the criteria — numbers, brevity, specificity, banlist — apply
    /// equally to hook lines).
    pub hook_line: String,
    /// Remainder of the caption — specifics, context, reaction. ≤230 chars.
    pub body: String,
    /// Whether this candidate uses the provided money-quote in its hook.
    /// Tracked so callers can filter / prefer quote-driven variants.
    #[serde(default)]
    pub uses_money_quote: bool,
    /// Combined score: `hook_score + body_score`. Range roughly 0.0–1.10.
    /// 0.0 = banlist hit on the hook (hard reject).
    #[serde(default)]
    pub score: f32,
}

/// Collapse a Wave 3 `CaptionCandidate` (hook + body) into the legacy
/// `CaptionVariant` (single `text`) shape that frontend + DB currently expect.
/// Callers that want the new two-part structure should read the candidate
/// directly; this is the adapter for code paths mid-migration.
pub fn caption_candidate_to_variant(candidate: &CaptionCandidate, selected_mode: &str) -> CaptionVariant {
    let hook = candidate.hook_line.trim();
    let body = candidate.body.trim();
    let text = match (hook.is_empty(), body.is_empty()) {
        (false, false) => format!("{} {}", hook, body),
        (false, true)  => hook.to_string(),
        (true, false)  => body.to_string(),
        (true, true)   => String::new(),
    };
    CaptionVariant {
        mode: selected_mode.to_string(),
        label: mode_label(selected_mode).to_string(),
        text,
    }
}

// ═══════════════════════════════════════════════════════════════════
//  Free-path title generation (Phase 12 Wave 3c)
// ═══════════════════════════════════════════════════════════════════
//
//  `free_title()` is the Free-path title generator. When a Twitch
//  community clip's title is available (the viewer's own wit, free
//  for us to reuse), we pass it through after a minimal sanity check:
//  length cap, slur filter, empty check. Otherwise fall back to a
//  simple synthesis from the event summary.
//
//  Per Wave 3 decision 5 in §12d of PHASE12_PROMPT_DIFF.md, the slur
//  banlist is intentionally minimal — Twitch already moderates its own
//  community clips. We only need to catch the rare bad case where
//  something slips through and would embarrass us on TikTok/YouTube.

/// Slur banlist for community-clip titles. Minimal by design — see
/// decision 5 in §12d. Case-insensitive match on whole words.
///
/// Intentionally omitted: common gaming profanity ("fuck", "shit",
/// etc.) that Twitch moderation explicitly allows in titles. Our filter
/// exists to catch what Twitch missed, not re-moderate.
const COMMUNITY_TITLE_SLUR_BANLIST: &[&str] = &[
    // Racial slurs
    "n1gger", "n1gga", "nigger", "nigga",
    // Homophobic / transphobic slurs
    "faggot", "tranny",
    // Ableist slurs (strongest)
    "retard", "retarded",
];

/// Generate a Free-path title for a clip.
///
/// If a community clip title is available AND passes sanity checks,
/// return it verbatim (truncated to 60 chars at a word boundary).
/// Otherwise synthesize a simple title from the event summary.
pub fn free_title(
    community_clip_title: Option<&str>,
    event_summary: &str,
    tags: &[String],
) -> String {
    if let Some(title) = community_clip_title {
        if let Some(clean) = sanitize_community_title(title) {
            return clean;
        }
    }
    synthesize_free_title(event_summary, tags)
}

/// Validate and lightly normalize a community-clip title.
/// Returns None if the title:
/// - is empty / whitespace-only
/// - contains a banned slur
///
/// When accepted, the title is truncated at word boundary to ≤60 chars
/// to match the existing BYOK title length convention.
fn sanitize_community_title(title: &str) -> Option<String> {
    let trimmed = title.trim();
    if trimmed.is_empty() {
        return None;
    }
    if contains_banned_slur(trimmed) {
        return None;
    }
    Some(truncate_title_at_word_boundary(trimmed, 60))
}

/// Case-insensitive whole-word slur match. Splits on non-alphanumeric
/// characters so that `"N1gger-style"` still catches the slur token.
fn contains_banned_slur(title: &str) -> bool {
    let lower = title.to_lowercase();
    for token in lower.split(|c: char| !c.is_ascii_alphanumeric()) {
        if COMMUNITY_TITLE_SLUR_BANLIST.contains(&token) {
            return true;
        }
    }
    false
}

/// Truncate at word boundary to ≤max_chars. Preserves words when possible,
/// drops the trailing fragment if the cut would land mid-word, appends
/// nothing (no ellipsis — titles look better without).
fn truncate_title_at_word_boundary(title: &str, max_chars: usize) -> String {
    if title.chars().count() <= max_chars {
        return title.to_string();
    }
    let truncated: String = title.chars().take(max_chars).collect();
    match truncated.rfind(' ') {
        Some(space) if space > max_chars / 2 => truncated[..space].trim_end().to_string(),
        _ => truncated,
    }
}

/// Minimal Free-path title synthesis. Capitalizes the first letter of
/// the event summary, drops a trailing period if present, and caps at
/// 60 chars to match the BYOK title convention.
///
/// `tags` is currently unused — reserved for future signal-driven
/// shaping (e.g. prepending "ACE:" for ace tags). Wave 3c keeps this
/// function minimal per decision 6 — the matrix already made the
/// event summary presentable.
fn synthesize_free_title(event_summary: &str, _tags: &[String]) -> String {
    let trimmed = event_summary.trim().trim_end_matches('.');
    if trimmed.is_empty() {
        return "clip moment".to_string();
    }

    // Capitalize the first alphabetic character, leave the rest alone.
    // Using chars() rather than bytes() to handle unicode safely.
    let mut chars = trimmed.chars();
    let capitalized = match chars.next() {
        Some(first) => first.to_uppercase().chain(chars).collect::<String>(),
        None => String::new(),
    };

    truncate_title_at_word_boundary(&capitalized, 60)
}

// ═══════════════════════════════════════════════════════════════════
//  LLM-based caption generation (BYOK)
// ═══════════════════════════════════════════════════════════════════
//
//  When a Claude API key is available, captions are generated by the
//  model instead of the pattern system.  One API call produces all 5
//  captions with mode-specific instructions.  Falls back to the
//  pattern system if the key is missing or the call fails.

/// System prompt shared by caption and title generation.
pub const LLM_SYSTEM_PROMPT: &str = "You are a gaming content creator writing captions for your own clips on TikTok, YouTube Shorts, and Instagram Reels. You have a sharp sense of humor, you're self-aware, and you talk like a real gamer \u{2014} not a brand account. You've watched the clip and you're writing about YOUR experience. First person. Lowercase is fine. You never use hashtags. You keep it under 280 characters.";

/// Human-readable label for each caption mode.
fn mode_label(mode: &str) -> &'static str {
    match mode {
        "direct_quote"     => "Quote",
        "blame"            => "Blame",
        "internal_thought" => "Thought",
        "observation"      => "Observe",
        "minimal"          => "Minimal",
        "punchy"           => "Punchy",
        "clean"            => "Clean",
        "funny"            => "Funny",
        "hype"             => "Hype",
        "search"           => "SEO",
        _ => "Caption",
    }
}

/// Instruction block describing a single tone, with examples.
fn tone_instruction(mode: &str) -> &'static str {
    match mode {
        "direct_quote"     => "TONE: Quote \u{2014} The transcript is your goldmine. Find the funniest or most dramatic line and use it FULLY \u{2014} don't chop it down to 3 words. Use enough of the quote so it's funny on its own. Then add a short reaction or framing. Examples: \"my friend really said 'what happened to gamers having shame' while I'm out here streaming at 2am\", \"'back in my day we had shame' \u{2014} sir this is Dead by Daylight\", \"he hit us with 'what happened to gamers' like we didn't already know\"",
        "blame"            => "TONE: Blame \u{2014} You're tilted. Blame your teammates, the game, the devs, matchmaking, your internet, your mouse, ANYTHING but yourself (or ironically blame yourself). Frustrated but funny. Examples: \"my team really watched that happen in 4k\", \"riot looked at my MMR and laughed\", \"i'm not bad the game is just better than me\", \"this is what peak matchmaking looks like apparently\"",
        "internal_thought" => "TONE: Thought \u{2014} Existential gamer moment. You're reflecting on what just happened like it changed you as a person. Dramatic, philosophical, a little unhinged. First person. Examples: \"i think about this play at 3am\", \"this is the moment i knew i peaked\", \"i've been staring at the ceiling since this happened\", \"some rounds teach you about yourself\"",
        "observation"      => "TONE: Observe \u{2014} You're narrating what happened like a nature documentary or a sports commentator. Third person or detached. Dry humor. Examples: \"man really walked into that like it was his first day\", \"the confidence followed by the immediate failure is poetic\", \"he said it with his whole chest too\", \"that was the exact wrong decision at the exact wrong time\"",
        "minimal"          => "TONE: Minimal \u{2014} 5 words or less. Gut punch. No explanation needed. The clip speaks for itself. Examples: \"nah.\", \"pain.\", \"we don't talk about this\", \"i'm done\", \"that's enough for today\"",
        "punchy"           => "TONE: Punchy \u{2014} High-energy, attention-grabbing, hard-hitting. Front-load the most exciting moment. Short sentences, strong verbs, zero filler. Focus on the ACTION that happened, not what was said. Examples: \"pushed through smoke and dropped all three\", \"one bullet. one kill. one tilted lobby.\", \"turned a 1v3 into a highlight reel\"",
        "clean"            => "TONE: Clean \u{2014} Polished, confident, no chaos. Write like a content creator who knows this clip is fire and doesn't need to oversell it. Calm energy, understated flex. Focus on the OUTCOME. Examples: \"calculated.\", \"clean rotations win rounds\", \"the read was right\", \"just another tuesday\"",
        "funny"            => "TONE: Funny \u{2014} Comedy first. Find the most absurd, ironic, or unexpected part of the clip and build the joke around THAT moment. Self-aware humor, exaggeration welcome. DON'T just quote \u{2014} add comedic framing. Examples: \"my game sense said go left. it lied.\", \"i peaked in 2019 and it's been downhill since\", \"the way i screamed and still died\"",
        "hype"             => "TONE: Hype \u{2014} Maximum energy. You're hyping yourself up. This is your best play and everyone needs to know. Bold, confident, slightly unhinged excitement. Focus on how INSANE the play was. Examples: \"DID THAT JUST HAPPEN?!\", \"i will never hit a shot like that again\", \"someone clip that. oh wait.\", \"that's the play of the year idc\"",
        "search"           => "TONE: SEO \u{2014} Written for discoverability. Include the game name, what happened, and searchable keywords naturally. Descriptive but still casual. Think: what would someone search to find this clip? Examples: \"insane valorant ace clutch 1v5 on haven\", \"dead by daylight killer rage quit after flashlight save\", \"overwatch 2 genji blade team wipe ranked\"",
        _ => "Write a short, punchy caption for this gaming clip.",
    }
}

/// Generate a single caption for a specific tone via the Claude/OpenAI/Gemini API.
///
/// Accepts the user's selected model from Settings instead of hardcoding one.
/// Only generates ONE caption for the requested tone — saves tokens and produces
/// better results since the model can focus.
pub async fn generate_llm(
    api_key: &str,
    model: &str,
    selected_mode: &str,
    event_summary: &str,
    transcript_quote: Option<&str>,
    tone_label: &str,
    tags: &[String],
    full_transcript: Option<&str>,
    clip_title: &str,
    game_name: Option<&str>,
) -> Result<Vec<CaptionVariant>, AppError> {
    // Build transcript section — prefer full subtitle transcript, fall back to single quote
    let transcript_section = if let Some(ft) = full_transcript.filter(|t| !t.trim().is_empty()) {
        // Truncate to ~800 chars to give Claude enough context about what happened
        let truncated = if ft.len() > 800 { &ft[..800] } else { ft };
        format!("TRANSCRIPT (what was said in the clip):\n\"{}\"\n\n", truncated)
    } else if let Some(q) = transcript_quote {
        format!("The person said: \"{}\"\n\n", q)
    } else {
        String::new()
    };

    let tag_line = if tags.is_empty() {
        String::new()
    } else {
        format!("Detected signals: {}\n", tags.join(", "))
    };

    let title_line = if clip_title.is_empty() {
        String::new()
    } else {
        format!("CLIP TITLE: {}\n", clip_title)
    };

    let game_line = match game_name {
        Some(name) if !name.is_empty() => {
            log::info!("[generate_llm] Game name received: {}", name);
            format!("GAME: {}\n", name)
        },
        _ => {
            log::info!("[generate_llm] No game name provided");
            String::new()
        },
    };

    let game_context = match game_name {
        Some(name) if !name.is_empty() => format!(" This is a {} clip — reference the game naturally where it fits.", name),
        _ => String::new(),
    };

    let game_style = match tone_label {
        "FPS / competitive shooter" => format!("Use competitive/tactical wording: pushed, dropped, one-tapped, rotated. Fast, clipped sentences.{}", game_context),
        "horror / survival" => format!("Use dread/survival wording: the dark, behind me, that noise, nope. Tense, breathless phrasing.{}", game_context),
        "cozy / chaotic casual" => format!("Use chaotic-wholesome wording: whoops, the kitchen, the plan, on fire. Light, exasperated phrasing.{}", game_context),
        "social / party / co-op" => format!("Use group-dynamics wording: the team, whose fault, trust broken, voted out. Accusatory, social phrasing.{}", game_context),
        _ => format!("Use plain streamer wording. No genre-specific flavor.{}", game_context),
    };

    let tone_block = tone_instruction(selected_mode);

    let prompt = format!(
        r#"Write ONE caption for my gaming clip.

GENRE: {tone}
{title}{game}WHAT HAPPENED: {event}
{transcript}{tags}
{tone_block}

STYLE GUIDE: {style}

RULES:
- Reference specific moments, dialogue, or reactions from the transcript — write like you watched the clip
- When quoting from the transcript, USE ENOUGH OF THE QUOTE for it to make sense and be funny. Don't chop a great line into 3 words. If someone said "what happened to gamers having shame doing this" — use the full line or close to it, not just "no shame"
- The caption should be specific to THIS clip — if someone reading the caption can't tell which clip it's from, it's too generic. Don't write captions that could apply to any random clip from the same game
- If the transcript has a funny, dramatic, or memorable line — that's your material. Build the caption around what was ACTUALLY SAID
- HARD LIMIT: 280 characters maximum. Count carefully. Most great captions are 80-180 characters. No hashtags. 1-2 emojis max (optional, only if natural)
- BANNED: "this happened", "caught on stream", "this was crazy", "just happened", "watch this", "you need to see this", "you won't believe", "check this out", "insane clip"

Respond with ONLY the caption. No quotes, no labels, nothing else."#,
        tone = tone_label,
        title = title_line,
        game = game_line,
        event = event_summary,
        transcript = transcript_section,
        tags = tag_line,
        tone_block = tone_block,
        style = game_style,
    );

    let client = reqwest::Client::new();
    let body = serde_json::json!({
        "model": model,
        "max_tokens": 256,
        "system": LLM_SYSTEM_PROMPT,
        "messages": [{
            "role": "user",
            "content": prompt,
        }]
    });

    log::debug!("Transcript being sent: \"{}\"", transcript_section.trim());
    log::debug!("Caption API Request:");
    log::debug!("Model: {}", model);
    log::debug!("Mode: {}", selected_mode);
    log::debug!("System: {}", LLM_SYSTEM_PROMPT);
    log::debug!("User message:\n{}", prompt);
    log::debug!("--- END Caption API Request ---");

    let resp = client
        .post("https://api.anthropic.com/v1/messages")
        .header("x-api-key", api_key)
        .header("anthropic-version", "2023-06-01")
        .header("content-type", "application/json")
        .json(&body)
        .send()
        .await
        .map_err(|e| AppError::Api(format!("Claude caption request failed: {e}")))?;

    if !resp.status().is_success() {
        let status = resp.status();
        let body = resp.text().await.unwrap_or_default();
        return Err(AppError::Api(format!("Claude API {}: {}", status, &body[..body.len().min(200)])));
    }

    let resp_json: serde_json::Value = resp.json().await
        .map_err(|e| AppError::Api(format!("Failed to parse Claude response: {e}")))?;

    let text = resp_json["content"][0]["text"]
        .as_str()
        .ok_or_else(|| AppError::Api("No text in Claude response".into()))?
        .trim()
        .to_string();

    if text.is_empty() {
        return Err(AppError::Api("Claude returned empty caption".into()));
    }

    // Strip surrounding quotes if the model wrapped the caption in them
    let cleaned = text.trim_matches('"').trim_matches('\'').trim().to_string();

    // Hard-enforce 280 character limit — LLMs are bad at counting chars
    let enforced = if cleaned.chars().count() > 280 {
        // Try to truncate at the last sentence/phrase boundary before 280
        let truncated: String = cleaned.chars().take(277).collect();
        if let Some(pos) = truncated.rfind(|c: char| c == '.' || c == '!' || c == '?' || c == '\n') {
            truncated[..=pos].trim().to_string()
        } else if let Some(pos) = truncated.rfind(' ') {
            // No sentence end — break at last space and add ellipsis
            format!("{}…", truncated[..pos].trim())
        } else {
            format!("{}…", truncated.trim())
        }
    } else {
        cleaned
    };

    let label = mode_label(selected_mode).to_string();

    log::debug!("Caption RESULT — mode: {}, len: {}, text: \"{}\"", selected_mode, enforced.chars().count(), enforced);

    Ok(vec![CaptionVariant {
        mode: selected_mode.to_string(),
        label,
        text: enforced,
    }])
}

/// Generate a clip title via the Claude API.
///
/// Returns a single short, punchy title (max 60 chars) that a gaming
/// content creator would use.  Falls back to None on any failure.
pub async fn generate_llm_title(
    api_key: &str,
    model: &str,
    event_summary: &str,
    full_transcript: Option<&str>,
    tags: &[String],
    game_name: Option<&str>,
) -> Result<String, AppError> {
    let transcript_section = if let Some(ft) = full_transcript.filter(|t| !t.trim().is_empty()) {
        let truncated = if ft.len() > 800 { &ft[..800] } else { ft };
        format!("TRANSCRIPT:\n\"{}\"\n\n", truncated)
    } else {
        String::new()
    };

    // Randomly pick a title angle category each call so consecutive
    // regenerations explore different aspects of the clip.
    let angles = [
        ("REACTION", "Focus on the streamer's emotional reaction — shock, panic, disbelief, joy. Example style: \"my heart actually stopped\""),
        ("GAMEPLAY", "Focus on what physically happened in the game — the play, the kill, the fail. Example style: \"jumped into a 1v3 and somehow lived\""),
        ("QUOTE", "Use or paraphrase a funny/memorable line from the transcript. Example style: \"back in my day gamers had honor\""),
        ("ABSURDITY", "Focus on how ridiculous or unexpected the situation was. Example style: \"streaming at 2am was a mistake\""),
        ("HOOK", "Write a dramatic hook that creates curiosity — make people NEED to watch. Example style: \"wait for the ending\" or \"this should not have worked\""),
        ("SELF-DEPRECATING", "Self-deprecating humor from the streamer's perspective. Example style: \"this is why i'm hardstuck\" or \"i deserve this\""),
    ];

    use std::time::SystemTime;
    let seed = SystemTime::now()
        .duration_since(SystemTime::UNIX_EPOCH)
        .map(|d| d.as_nanos() as usize)
        .unwrap_or(0);
    let (angle_name, angle_desc) = angles[seed % angles.len()];

    // Also pick a random transcript word to explicitly ban, further
    // preventing the model from fixating on one dominant theme.
    let avoid_word = full_transcript
        .filter(|t| !t.trim().is_empty())
        .and_then(|t| {
            let words: Vec<&str> = t.split_whitespace()
                .filter(|w| w.len() >= 4)
                .map(|w| w.trim_matches(|c: char| !c.is_alphanumeric()))
                .filter(|w| !w.is_empty())
                .collect();
            if words.is_empty() {
                None
            } else {
                // Use a different part of the seed so it doesn't correlate with angle selection
                Some(words[(seed / 7) % words.len()].to_lowercase())
            }
        });

    let avoid_line = match &avoid_word {
        Some(word) if !word.is_empty() => format!(
            "BANNED WORD: Do NOT use the word \"{}\" or synonyms of it in your title.\n",
            word
        ),
        _ => String::new(),
    };

    let tag_line = if tags.is_empty() {
        String::new()
    } else {
        format!("Viral signals: {}\n", tags.join(", "))
    };

    let game_line = match game_name {
        Some(name) if !name.is_empty() => format!("GAME: {}\n", name),
        _ => String::new(),
    };

    let prompt = format!(
        r#"Generate ONE short punchy title (max 60 characters) for this gaming clip.

{game}WHAT HAPPENED: {event}
{transcript}{tags}
YOUR ANGLE FOR THIS TITLE: {angle_name}
{angle_desc}

You MUST write the title from the {angle_name} angle described above. Do NOT default to summarizing the transcript's most obvious theme.
{avoid}
RULES:
- Maximum 60 characters. Shorter is better.
- Write like a real gaming content creator — lowercase is fine, be casual.
- No hashtags, no emojis, no clickbait phrases like "you won't believe".
- No ALL CAPS.
- The title should make someone want to click.

Respond with ONLY the title. No quotes, no explanation — just the title text."#,
        game = game_line,
        event = event_summary,
        transcript = transcript_section,
        tags = tag_line,
        angle_name = angle_name,
        angle_desc = angle_desc,
        avoid = avoid_line,
    );

    let client = reqwest::Client::new();
    let body = serde_json::json!({
        "model": model,
        "max_tokens": 80,
        "system": LLM_SYSTEM_PROMPT,
        "messages": [{
            "role": "user",
            "content": prompt,
        }]
    });

    log::debug!("Title API Request (angle: {}, avoid: {:?}):", angle_name, avoid_word);
    log::debug!("Model: {}", model);
    log::debug!("System: {}", LLM_SYSTEM_PROMPT);
    log::debug!("User message:\n{}", prompt);
    log::debug!("--- END Title API Request ---");

    let resp = client
        .post("https://api.anthropic.com/v1/messages")
        .header("x-api-key", api_key)
        .header("anthropic-version", "2023-06-01")
        .header("content-type", "application/json")
        .json(&body)
        .send()
        .await
        .map_err(|e| AppError::Api(format!("Claude title request failed: {e}")))?;

    if !resp.status().is_success() {
        let status = resp.status();
        let body = resp.text().await.unwrap_or_default();
        return Err(AppError::Api(format!("Claude API {}: {}", status, &body[..body.len().min(200)])));
    }

    let resp_json: serde_json::Value = resp.json().await
        .map_err(|e| AppError::Api(format!("Failed to parse Claude title response: {e}")))?;

    let text = resp_json["content"][0]["text"]
        .as_str()
        .ok_or_else(|| AppError::Api("No text in Claude title response".into()))?
        .trim()
        .to_string();

    if text.is_empty() {
        return Err(AppError::Api("Claude returned empty title".into()));
    }

    // Strip surrounding quotes if the model wrapped it
    let cleaned = text.trim_matches('"').trim_matches('\'').trim().to_string();

    // Enforce 60 char limit
    let final_title = if cleaned.chars().count() > 60 {
        let truncated: String = cleaned.chars().take(60).collect();
        if let Some(space) = truncated.rfind(' ') {
            truncated[..space].to_string()
        } else {
            truncated
        }
    } else {
        cleaned
    };

    log::debug!("Title RESULT — len: {}, text: \"{}\"", final_title.chars().count(), final_title);

    Ok(final_title)
}

// ═══════════════════════════════════════════════════════════════════
//  Money-quote extraction — Free path (Phase 12 Wave 2)
// ═══════════════════════════════════════════════════════════════════
//
//  Pure heuristic, no network. Slides a 2–6 word window over each
//  transcript segment, scores candidates on:
//
//  - emotional keyword hit  (uses ranker's curated list, +0.40)
//  - peak RMS during phrase (when samples available, +0–0.40)
//  - brevity bonus          (shorter = punchier, +0–0.20)
//
//  Returns the best-scoring phrase above threshold 0.5, or None.
//
//  See section 3b of docs/PHASE12_PROMPT_DIFF.md.

/// Extract a money-quote from transcript segments using a pure heuristic.
///
/// `transcript_segments`: `(start_sec, end_sec, text)` for each segment.
/// `rms_samples`: optional `(timestamp_sec, rms)` audio samples; when
/// `None`, the RMS factor falls back to a constant 0.5.
///
/// Returns `Some(phrase)` if any 2–6 word phrase scores above 0.5,
/// else `None`.
pub fn extract_money_quote_free(
    transcript_segments: &[(f64, f64, String)],
    rms_samples: Option<&[(f64, f32)]>,
) -> Option<String> {
    use crate::detection::ranker::DEFAULT_EMOTIONAL_WORDS;

    const SCORE_THRESHOLD: f32 = 0.5;
    const DEFAULT_RMS_WHEN_NO_SAMPLES: f32 = 0.5;

    let mut best: Option<(f32, String)> = None;

    for (start, end, text) in transcript_segments {
        let words: Vec<&str> = text.split_whitespace().collect();
        if words.len() < 2 {
            continue;
        }

        // Pre-compute the peak RMS once per segment — same across all windows.
        let rms_during = match rms_samples {
            Some(samples) => samples
                .iter()
                .filter(|(t, _)| t >= start && t <= end)
                .map(|(_, r)| *r)
                .fold(0.0_f32, f32::max),
            None => DEFAULT_RMS_WHEN_NO_SAMPLES,
        };

        for window_size in 2..=6 {
            if window_size > words.len() {
                break;
            }
            for start_idx in 0..=(words.len() - window_size) {
                let phrase_words = &words[start_idx..start_idx + window_size];

                let keyword_hit = phrase_words.iter().any(|w| {
                    let clean = w
                        .trim_matches(|c: char| !c.is_alphabetic())
                        .to_lowercase();
                    DEFAULT_EMOTIONAL_WORDS.iter().any(|k| clean == *k)
                });

                // Brevity: 2 words → 0.20, 6 words → 0.00, linear.
                let brevity_bonus = (6 - window_size) as f32 / 4.0 * 0.20;

                let score = (if keyword_hit { 0.40 } else { 0.0 })
                    + (rms_during.clamp(0.0, 1.0) * 0.40)
                    + brevity_bonus;

                if score >= SCORE_THRESHOLD
                    && best.as_ref().map_or(true, |(best_s, _)| score > *best_s)
                {
                    best = Some((score, phrase_words.join(" ")));
                }
            }
        }
    }

    best.map(|(_, phrase)| phrase)
}

// ═══════════════════════════════════════════════════════════════════
//  Title generation — new API (Phase 12 Wave 2)
// ═══════════════════════════════════════════════════════════════════
//
//  Produces 5 title candidates in one Claude API call. Each candidate
//  must match one of three structural patterns (StakeArrowOutcome /
//  EmotionColonDetail / QuoteTwist). Candidates are pre-scored via
//  `detection::ranker::score_title` and sorted descending, so callers
//  can just take `candidates[0]`.
//
//  The old `generate_llm_title` (single-string output) is left in
//  place byte-for-byte. `commands/captions.rs` still calls it; caller
//  migration is a separate tiny follow-up after Wave 2 is proven.
//
//  See section 11b of docs/PHASE12_PROMPT_DIFF.md.

/// Generate 5 title candidates, ranker-scored and sorted.
///
/// `money_quote` (optional): if present, AT MOST 1 of 5 candidates may use it
/// (post-2026-04 behavior; the original "2 of 5" bias caused regen stickiness).
/// In the 6-pattern taxonomy, quote-led hooks typically land as
/// `TitlePattern::AftermathConfession` (self-quote) or `::Observational` (quoted reaction).
/// `streamer_history` (optional): past titles used for overlap check in
/// the prompt's "avoid repetition" instruction AND in the ranker's
/// history-overlap scoring. Pass `None` until Phase 11 populates it.
/// `target_platform`: `None` defaults to `Platform::TikTok` for scoring.
/// Callers that know the publish target (Shorts / Reels) should pass it
/// explicitly so length scoring is accurate.
pub async fn generate_llm_titles(
    api_key: &str,
    model: &str,
    event_summary: &str,
    money_quote: Option<&str>,
    full_transcript: Option<&str>,
    tags: &[String],
    game_name: Option<&str>,
    streamer_history: Option<&[String]>,
    target_platform: Option<Platform>,
) -> Result<Vec<TitleCandidate>, AppError> {
    const TRANSCRIPT_CHAR_LIMIT: usize = 800;

    // ── Assemble prompt sections ──────────────────────────────

    let game_line = match game_name {
        Some(name) if !name.is_empty() => format!("GAME: {}\n", name),
        _ => String::new(),
    };

    let transcript_section = match full_transcript.filter(|t| !t.trim().is_empty()) {
        Some(ft) => {
            let truncated: String = ft.chars().take(TRANSCRIPT_CHAR_LIMIT).collect();
            format!("TRANSCRIPT:\n\"{}\"\n\n", truncated)
        }
        None => String::new(),
    };

    let money_quote_line = match money_quote {
        Some(q) if !q.trim().is_empty() => format!("MONEY QUOTE (available — use in AT MOST 1 of 5): \"{}\"\n", q),
        _ => String::new(),
    };

    let tag_line = if tags.is_empty() {
        String::new()
    } else {
        format!("SIGNAL TAGS: {}\n", tags.join(", "))
    };

    let history_line = match streamer_history {
        Some(h) if !h.is_empty() => format!(
            "STREAMER RECENT TITLES (STRICT anti-repeat rules — none of your 5 candidates may:\n\
             - Open with the same word as any of these\n\
             - Exceed 50% token overlap with any of these\n\
             - Use the same Emotion word as any of these — if 'Humbled:' appears below, no candidate may open with 'Humbled:'):\n{}\n",
            h.iter().take(10).cloned().collect::<Vec<_>>().join("\n"),
        ),
        _ => "STREAMER RECENT TITLES: none yet\n".into(),
    };

    let prompt = format!(
        r#"You are writing titles for a gaming short-form clip (YouTube Shorts / TikTok).
Produce 5 candidates that a scroll-tired viewer would STOP for. Return JSON only.

{game}WHAT HAPPENED: {event}
{money_quote}{transcript}{tags}{history}
HOW REAL HIGH-ENGAGEMENT GAMING TITLES LOOK (from actual top-performing Shorts):
- "actually clean" — TenZ, 1.3M views (Valorant ace)
- "gonna sleep on the couch again" — TenZ, 1.2M (duo clip with girlfriend)
- "dialed in" — TenZ, 492k (aim play)
- "couldn't help myself" — TenZ, 3.2M (reaction)
- "destroyed C9 but lost a friend" — TenZ, 2.8M (pro match)
- "Meg learnt to fly" — OtzStreams, 26k (DBD clip)
- "Famous last words" — OtzStreams, 66k
- "The WORST hex in DBD" — OtzStreams, 432k
- "The FASTEST totem cleanse in DBD" — OtzStreams, 597k
- "Don't blind Legion when he's vaulting" — OtzStreams, 139k
- "Why has nobody left the bus?" — Jynxzi, 356k
- "As soon as he realized" — Jynxzi, 1.1M
- "streamer discovers Pose 28" — OtzStreams, 32k
- "Every. Single. Time." — OtzStreams, 49k

Notice what they SHARE: lowercase or sentence case, no arrows/em-dashes, no "POV:" prefix,
concrete anchors (C9, Meg, Legion, DBD, hex, totem), short and confident, post-clip voice.
They DON'T stuff a metaphor or over-explain. They DON'T rhyme or do parallel structure.

CONTEXT RULE (non-negotiable):
Every candidate MUST contain at least ONE concrete anchor from the clip: a named character,
boss, mechanic, map, weapon, player, or game object. "Elden Ring moment" is NOT an anchor.
"Margit" / "fog gate" / "mimic tear" / "grab attack" / "broken stance" are anchors.

PICK ONE OF SIX TYPES PER CANDIDATE. Default to types 1 and 2 unless the clip content
specifically calls for another. Spread across at least 3 different types.

1. QUIET_FLEX (DEFAULT for clutch / win / skill clips)
   2–4 word understatement, usually post-clip. Max 25 characters.
   Anchor the flex to the moment: "cleanest fog gate entry", "mimic tear actually clean",
   "that worked", "no notes", "peak elden ring", "dialed in on the parry".

2. AFTERMATH_CONFESSION (DEFAULT for fail / reaction / self-deprecating clips)
   First-person past-tense or resigned present. 4–9 words. No "POV:" prefix.
   Include the anchor: "should've trusted the mimic", "ran at Malenia with zero flasks",
   "gonna uninstall after that grab", "spent all my runes on nothing", "couldn't help myself".

3. OBSERVATIONAL (when someone/something OTHER than the clipper is the subject)
   Third-person narration of what that subject did. 4–10 words.
   Examples: "Meg learnt to fly", "streamer discovers the fog gate",
   "invader picked the worst hill to die on", "chat realized before i did".

4. TECH_CALLOUT (only when the clip reveals a technique, bug, or strategy)
   Imperative or declarative about a named mechanic. 4–10 words.
   Examples: "don't parry Rykard's second phase", "new bleed tech just dropped",
   "the jump attack has iframes actually".

5. SPECIFIC_SUPERLATIVE (only when the clip is genuinely extreme)
   "worst/fastest/most/cleanest X ever" pinned to a NAMED mechanic or character.
   Do NOT use if the clip isn't actually extreme.
   Examples: "the WORST hex in DBD", "fastest Radahn phase 2 i've seen",
   "cleanest Margit parry on this channel".

6. CURIOSITY_QUESTION (only when the clip has a clear "wait, what?" beat)
   Specific unanswered question about something in the clip. 5–12 words.
   Examples: "why is Godrick doing that", "name a worse boss arena",
   "who told him to do that".

HARD BANS (instant reject):
- No arrows (->, →). No em-dashes (—) as a separator. No colons as a separator unless
  quoting direct speech.
- No "POV:" prefix. Real high-engagement titles do NOT start with "POV:".
- No title-case "X Moment That Hits Different" / "X Goes Crazy" / "X Is Insane" padding.
- Banned words: insane, crazy, epic, literally, wild, shocking, unbelievable, omg,
  you won't believe, mind-blowing, must see, check this, watch this, hits different,
  goes hard, no cap, lowkey, fr.
- Banned emotion labels used alone: Speechless, Stunned, Rattled, Shook, Floored,
  Shocked, Paralyzed, Frozen, Numb, Silenced, Gutted, Wrecked, Broken, Humbled,
  Mortified, Crushed, Devastated, Defeated. (If you reach for one of these, you're
  using the wrong pattern. Switch to QUIET_FLEX or AFTERMATH_CONFESSION.)

LENGTH:
- QUIET_FLEX: max 25 chars. Aim shorter.
- All other types: max 60 chars. Aim for 30-50.
- No trailing period. No hashtags. No emojis. No ALL CAPS words except in SPECIFIC_SUPERLATIVE
  (where "WORST"/"FASTEST"/"BEST" can single-word emphasize).

DIVERSITY (strict — violated output will be rejected):
- 5 candidates, 5 DIFFERENT opening words, spread across at least 3 different types.
- At least 1 QUIET_FLEX candidate. At least 1 AFTERMATH_CONFESSION or OBSERVATIONAL candidate.
- Never produce 5 variations of the same idea. If one candidate is about silence,
  no other may also be about silence.
- If a STREAMER RECENT TITLES list is provided above, none of your candidates may open
  with the same word or follow the same shape as any listed title.

OUTPUT — JSON only, no prose, no markdown fence:
{{"candidates": [
  {{"pattern": "QUIET_FLEX", "text": "..."}},
  {{"pattern": "AFTERMATH_CONFESSION", "text": "..."}},
  {{"pattern": "OBSERVATIONAL", "text": "..."}},
  {{"pattern": "QUIET_FLEX", "text": "..."}},
  {{"pattern": "TECH_CALLOUT", "text": "..."}}
]}}"#,
        game = game_line,
        event = event_summary,
        money_quote = money_quote_line,
        transcript = transcript_section,
        tags = tag_line,
        history = history_line,
    );

    // ── Send request ──────────────────────────────────────────

    let client = reqwest::Client::new();
    let body = serde_json::json!({
        "model": model,
        "max_tokens": 400,
        "system": LLM_SYSTEM_PROMPT,
        "messages": [{"role": "user", "content": prompt}],
    });

    log::debug!("generate_llm_titles request - model: {}, history: {}",
        model,
        streamer_history.map(|h| h.len()).unwrap_or(0),
    );

    let resp = client
        .post("https://api.anthropic.com/v1/messages")
        .header("x-api-key", api_key)
        .header("anthropic-version", "2023-06-01")
        .header("content-type", "application/json")
        .json(&body)
        .send()
        .await
        .map_err(|e| AppError::Api(format!("Claude titles request failed: {e}")))?;

    if !resp.status().is_success() {
        let status = resp.status();
        let body = resp.text().await.unwrap_or_default();
        return Err(AppError::Api(format!(
            "Claude API {}: {}",
            status,
            &body[..body.len().min(200)]
        )));
    }

    let resp_json: serde_json::Value = resp
        .json()
        .await
        .map_err(|e| AppError::Api(format!("Failed to parse Claude titles response: {e}")))?;

    let text = resp_json["content"][0]["text"]
        .as_str()
        .ok_or_else(|| AppError::Api("No text in Claude titles response".into()))?;

    // ── Parse JSON (try raw, then markdown-fence fallback) ────

    let parsed: TitlesResponse = match serde_json::from_str(text.trim()) {
        Ok(p) => p,
        Err(_) => {
            let json_str = extract_json_from_markdown(text)?;
            serde_json::from_str(&json_str)
                .map_err(|e| AppError::Api(format!("Malformed titles JSON: {e}")))?
        }
    };

    if parsed.candidates.is_empty() {
        return Err(AppError::Api("Claude returned zero title candidates".into()));
    }

    // ── Score via the ranker and sort ─────────────────────────

    let platform = target_platform.unwrap_or(Platform::TikTok);
    let empty_history: Vec<String> = Vec::new();
    let history_ref = streamer_history.unwrap_or(&empty_history);

    let ctx = crate::detection::ranker::RankerContext {
        streamer_history: history_ref,
        banned_words: crate::detection::ranker::DEFAULT_BANNED_WORDS,
        target_platform: platform,
        has_money_quote: money_quote.is_some(),
    };

    let mut scored: Vec<TitleCandidate> = parsed
        .candidates
        .into_iter()
        .map(|c| {
            // Per-pattern length bonus. QuietFlex wants 2-4 word understatements
            // (~15-25 chars) so the generic length_target (60) would silently
            // under-reward them; we re-center per pattern. All other patterns
            // already get a reasonable score from the global length rule.
            let len = c.text.chars().count();
            let length_bonus = match c.pattern {
                TitlePattern::QuietFlex => {
                    if len <= 25 { 0.15 }
                    else if len <= 35 { 0.05 }
                    else { -0.10 }
                }
                _ => 0.0,
            };
            TitleCandidate {
                score: crate::detection::ranker::score_title(&c.text, &ctx) + length_bonus,
                text: c.text,
                pattern: c.pattern,
            }
        })
        .collect();

    // Descending by score so candidates[0] is the winner.
    scored.sort_by(|a, b| b.score.partial_cmp(&a.score).unwrap_or(std::cmp::Ordering::Equal));

    log::debug!(
        "generate_llm_titles result - top score: {:.2}, pattern spread: {}",
        scored.first().map(|c| c.score).unwrap_or(0.0),
        scored
            .iter()
            .map(|c| format!("{:?}", c.pattern))
            .collect::<Vec<_>>()
            .join(","),
    );

    Ok(scored)
}

#[derive(serde::Deserialize)]
struct TitlesResponse {
    candidates: Vec<RawTitleCandidate>,
}

/// Intermediate shape — what the LLM returns per candidate before
/// ranker scoring. `score` is added in the pipeline, not the LLM.
#[derive(serde::Deserialize)]
struct RawTitleCandidate {
    text: String,
    pattern: TitlePattern,
}

// ═══════════════════════════════════════════════════════════════════
//  Caption generation — new API (Phase 12 Wave 3a)
// ═══════════════════════════════════════════════════════════════════
//
//  Produces 3 caption candidates per call. Each candidate is split
//  into `hook_line` (scroll-stopper, ≤50 chars) + `body` (≤230 chars).
//  Hashtags are NOT in the output — Wave 1 decision 4, they come from
//  the client-side `build_hashtags_v2()` function.
//
//  The old `generate_llm()` (single-caption output) is left byte-for-byte
//  identical for Wave 3a. Caller migration is a separate unified commit
//  after Wave 3c ships per Wave 3 decision 6.
//
//  See section 12a of docs/PHASE12_PROMPT_DIFF.md.

/// Generate 3 caption candidates for a clip, ranker-scored and sorted.
///
/// Arguments mirror the old `generate_llm()` signature with three
/// additions:
/// - `platform` (`Option<Platform>`, `None` defaults to TikTok) — drives
///   length scoring + prompt-side platform hint.
/// - `money_quote` — if present, 2 of 3 candidates should use it in the hook.
/// - `streamer_niche_tags` — passed to the prompt as context (also flows
///   into `build_hashtags_v2` on the caller side, not here).
///
/// Returns candidates sorted descending by `(hook_score + body_score)`.
/// `score = 0.0` means banlist hit on the hook — caller may choose to
/// drop those before presenting.
pub async fn generate_llm_caption(
    api_key: &str,
    model: &str,
    selected_mode: &str,
    platform: Option<Platform>,
    event_summary: &str,
    money_quote: Option<&str>,
    transcript_quote: Option<&str>,
    tone_label: &str,
    tags: &[String],
    full_transcript: Option<&str>,
    clip_title: &str,
    game_name: Option<&str>,
    streamer_niche_tags: &[String],
    avoid_caption: Option<&str>,
) -> Result<Vec<CaptionCandidate>, AppError> {
    const TRANSCRIPT_CHAR_LIMIT: usize = 800;

    // ── Assemble prompt sections ──────────────────────────────

    let platform_resolved = platform.unwrap_or(Platform::TikTok);
    let platform_line = format!("PLATFORM: {}\n", platform_resolved.display_name());

    let game_line = match game_name {
        Some(name) if !name.is_empty() => format!("GAME: {}\n", name),
        _ => String::new(),
    };

    let title_line = if clip_title.is_empty() {
        String::new()
    } else {
        format!("CLIP TITLE: {}\n", clip_title)
    };

    let transcript_section = match full_transcript.filter(|t| !t.trim().is_empty()) {
        Some(ft) => {
            let truncated: String = ft.chars().take(TRANSCRIPT_CHAR_LIMIT).collect();
            format!("TRANSCRIPT:\n\"{}\"\n\n", truncated)
        }
        None => match transcript_quote {
            Some(q) if !q.trim().is_empty() => format!("The person said: \"{}\"\n\n", q),
            _ => String::new(),
        },
    };

    let money_quote_line = match money_quote {
        Some(q) if !q.trim().is_empty() => format!(
            "MONEY QUOTE (available — use in AT MOST 1 of 3 hooks): \"{}\"\n",
            q
        ),
        _ => String::new(),
    };

    let tag_line = if tags.is_empty() {
        String::new()
    } else {
        format!("SIGNAL TAGS: {}\n", tags.join(", "))
    };

    let niche_line = if streamer_niche_tags.is_empty() {
        String::new()
    } else {
        format!("STREAMER NICHE: {}\n", streamer_niche_tags.join(", "))
    };

    let avoid_line = match avoid_caption {
        Some(prev) if !prev.trim().is_empty() => format!(
            "AVOID REPEATING (this is the current caption — your output must not be a close variant):\n\"{}\"\n\n",
            prev.trim()
        ),
        _ => String::new(),
    };

    let tone_block = tone_instruction(selected_mode);

    let prompt = format!(
        r#"Write 3 caption candidates for my gaming clip. Return JSON only.

{platform}{game}GENRE: {tone}
{title}WHAT HAPPENED: {event}
{money_quote}{transcript}{tags}{niche}{avoid}
MODE: {tone_block}

STRUCTURE - each candidate has two parts:
- hook_line: first ~50 characters. Active voice. Emotional driver.
  Scroll-stopper. Must be complete on its own when read alone.
- body: remainder (<230 chars). Specifics. Context. Reaction.

DIVERSITY (strict — your output will be rejected if violated):
- The 3 hooks MUST open with 3 DIFFERENT angles AND 3 DIFFERENT opening words.
- Angle menu: money-quote (AT MOST 1 of 3), observation about the moment,
  specific stake or detail, reaction framing, self-deprecation, meme/juxtaposition.
- The 3 bodies must differ in their core beat — not three variations of the same sentence.
- Never fabricate quotes. Only use the provided quote or transcript fragments.
- If "AVOID REPEATING" is shown above, none of the 3 candidates may open with the same
  word, use the same core image, or follow the same sentence shape as that caption.

AVOID (reads as AI filler):
- Stacking adjectives ("pure silence", "dead silence", "full silence" — pick one)
- Narrative trilogies ("no words. no plan. no commentary.")
- Over-explaining emotion ("deeply regretting", "knowing exactly what we signed up for")
- Recapping what the signal tags already say
- Starting every candidate with the same sentence shape

HARD LIMITS:
- hook_line: <=50 characters (will be client-side truncated if longer)
- body: <=230 characters
- hook_line + body: <=280 characters combined
- No hashtags in output (generated separately)

BANNED PHRASES (reject candidate):
this happened, caught on stream, this was crazy, just happened,
watch this, you need to see this, you won't believe, check this out,
insane clip, literally, epic

OUTPUT - JSON only, no prose, no markdown fence:
{{"candidates": [
  {{"hook_line": "...", "body": "...", "uses_money_quote": true|false}},
  {{"hook_line": "...", "body": "...", "uses_money_quote": true|false}},
  {{"hook_line": "...", "body": "...", "uses_money_quote": true|false}}
]}}"#,
        platform = platform_line,
        game = game_line,
        tone = tone_label,
        title = title_line,
        event = event_summary,
        money_quote = money_quote_line,
        transcript = transcript_section,
        tags = tag_line,
        niche = niche_line,
        avoid = avoid_line,
        tone_block = tone_block,
    );

    // ── Send request ──────────────────────────────────────────

    let client = reqwest::Client::new();
    let body = serde_json::json!({
        "model": model,
        "max_tokens": 600,
        "system": LLM_SYSTEM_PROMPT,
        "messages": [{"role": "user", "content": prompt}],
    });

    log::debug!(
        "generate_llm_caption request - model: {}, mode: {}, platform: {:?}, money_quote: {}",
        model,
        selected_mode,
        platform_resolved,
        money_quote.is_some(),
    );

    let resp = client
        .post("https://api.anthropic.com/v1/messages")
        .header("x-api-key", api_key)
        .header("anthropic-version", "2023-06-01")
        .header("content-type", "application/json")
        .json(&body)
        .send()
        .await
        .map_err(|e| AppError::Api(format!("Claude caption request failed: {e}")))?;

    if !resp.status().is_success() {
        let status = resp.status();
        let body = resp.text().await.unwrap_or_default();
        return Err(AppError::Api(format!(
            "Claude API {}: {}",
            status,
            &body[..body.len().min(200)]
        )));
    }

    let resp_json: serde_json::Value = resp
        .json()
        .await
        .map_err(|e| AppError::Api(format!("Failed to parse Claude caption response: {e}")))?;

    let text = resp_json["content"][0]["text"]
        .as_str()
        .ok_or_else(|| AppError::Api("No text in Claude caption response".into()))?;

    // ── Parse JSON (raw first, markdown-fence fallback) ───────

    let parsed: CaptionsResponse = match serde_json::from_str(text.trim()) {
        Ok(p) => p,
        Err(_) => {
            let json_str = extract_json_from_markdown(text)?;
            serde_json::from_str(&json_str)
                .map_err(|e| AppError::Api(format!("Malformed captions JSON: {e}")))?
        }
    };

    if parsed.candidates.is_empty() {
        return Err(AppError::Api("Claude returned zero caption candidates".into()));
    }

    // ── Score via the ranker + body heuristic, sort descending ─

    let ctx = crate::detection::ranker::RankerContext {
        streamer_history: &[],
        banned_words: crate::detection::ranker::DEFAULT_BANNED_WORDS,
        target_platform: platform_resolved,
        has_money_quote: money_quote.is_some(),
    };

    let mut scored: Vec<CaptionCandidate> = parsed
        .candidates
        .into_iter()
        .map(|c| {
            let hook_truncated = truncate_hook(&c.hook_line, 50);
            let hook_score = crate::detection::ranker::score_title(&hook_truncated, &ctx);
            let body_score = score_caption_body(&c.body);
            // Wave 3 fix: de-prefer money-quote-led candidates. Quote hooks nail the
            // ranker's brevity/specificity criteria so they would auto-win every regen
            // unless we put a thumb on the scale. 0.10 is enough to let a non-quote
            // candidate win when it's even roughly competitive on other dimensions,
            // but not so much that a genuinely great quote hook gets buried.
            let money_quote_penalty = if c.uses_money_quote && money_quote.is_some() {
                0.10
            } else {
                0.0
            };
            CaptionCandidate {
                hook_line: hook_truncated,
                body: c.body,
                uses_money_quote: c.uses_money_quote,
                score: hook_score + body_score - money_quote_penalty,
            }
        })
        .collect();

    scored.sort_by(|a, b| {
        b.score
            .partial_cmp(&a.score)
            .unwrap_or(std::cmp::Ordering::Equal)
    });

    log::debug!(
        "generate_llm_caption result - top score: {:.2}, candidates: {}",
        scored.first().map(|c| c.score).unwrap_or(0.0),
        scored.len(),
    );

    Ok(scored)
}

#[derive(serde::Deserialize)]
struct CaptionsResponse {
    candidates: Vec<RawCaptionCandidate>,
}

#[derive(serde::Deserialize)]
struct RawCaptionCandidate {
    hook_line: String,
    body: String,
    #[serde(default)]
    uses_money_quote: bool,
}

/// Client-side hook truncation. If the model overshoots the 50-char
/// target, we cut at the last word boundary within the limit and append
/// an ellipsis. Preserves the scroll-stopper contract.
fn truncate_hook(hook: &str, max_chars: usize) -> String {
    let len = hook.chars().count();
    if len <= max_chars {
        return hook.to_string();
    }
    let truncated: String = hook.chars().take(max_chars.saturating_sub(1)).collect();
    // Cut at last space if one exists near the end — otherwise hard cut.
    if let Some(space) = truncated.rfind(' ') {
        if space >= (max_chars / 2) {
            return format!("{}…", truncated[..space].trim_end());
        }
    }
    format!("{}…", truncated.trim_end())
}

/// Lightweight secondary score for the body. Kept small so the hook
/// score (which can reach 1.0 via the ranker) dominates sort order.
fn score_caption_body(body: &str) -> f32 {
    let len = body.chars().count();
    if len == 0 || len > 230 {
        return 0.0;
    }
    if len < 30 {
        // Too short — low-information body, hook is carrying everything.
        return 0.05;
    }
    0.10
}

// ═══════════════════════════════════════════════════════════════════
//  Money-quote extraction — BYOK path (Phase 12 Wave 2)
// ═══════════════════════════════════════════════════════════════════
//
//  Small separate API call — gated independently by `ai_for_titles ||
//  ai_for_captions` in the toggle framework (Phase 6.0). Returns the
//  model's best 2–6 word phrase from the transcript, with a confidence
//  floor of 0.6.
//
//  See section 3a of docs/PHASE12_PROMPT_DIFF.md.

/// Extract a money-quote via a BYOK LLM call.
///
/// Returns:
/// - `Err(e)` — API error (network failure, HTTP != 2xx, malformed response).
/// - `Ok(None)` — model said no quote qualifies, OR confidence < 0.6,
///   OR returned phrase failed the 2–6 word check.
/// - `Ok(Some(phrase))` — usable money-quote.
pub async fn extract_money_quote_llm(
    api_key: &str,
    model: &str,
    event_summary: &str,
    full_transcript: &str,
    tags: &[String],
) -> Result<Option<String>, AppError> {
    const CONFIDENCE_THRESHOLD: f32 = 0.6;
    const TRANSCRIPT_CHAR_LIMIT: usize = 800;

    let tag_line = if tags.is_empty() {
        String::new()
    } else {
        format!("SIGNALS: {}\n", tags.join(", "))
    };

    let truncated: String = full_transcript.chars().take(TRANSCRIPT_CHAR_LIMIT).collect();

    let prompt = format!(
        r#"Extract the single best "money quote" from this gaming clip transcript.
A money quote is a 2-6 word phrase worth prominently displaying on the clip
(title, caption, or video overlay).

WHAT HAPPENED: {event}
TRANSCRIPT: "{transcript}"
{tags}
CRITERIA:
- Must be 2 to 6 words total (strict)
- Must be something the streamer ACTUALLY said (no fabrication)
- Should be self-contained (makes sense out of context)
- Priority: memorable phrasing > on-topic > emotional reaction
- If nothing in transcript qualifies, return null

OUTPUT - JSON only, no prose, no markdown fence:
{{"quote": "...", "confidence": 0.0-1.0}}
or
{{"quote": null, "confidence": 0.0}}"#,
        event = event_summary,
        transcript = truncated,
        tags = tag_line,
    );

    let client = reqwest::Client::new();
    let body = serde_json::json!({
        "model": model,
        "max_tokens": 80,
        "system": LLM_SYSTEM_PROMPT,
        "messages": [{"role": "user", "content": prompt}],
    });

    log::debug!("money-quote LLM request — model: {}", model);

    let resp = client
        .post("https://api.anthropic.com/v1/messages")
        .header("x-api-key", api_key)
        .header("anthropic-version", "2023-06-01")
        .header("content-type", "application/json")
        .json(&body)
        .send()
        .await
        .map_err(|e| AppError::Api(format!("Money-quote request failed: {e}")))?;

    if !resp.status().is_success() {
        let status = resp.status();
        let body = resp.text().await.unwrap_or_default();
        return Err(AppError::Api(format!(
            "Claude API {}: {}",
            status,
            &body[..body.len().min(200)]
        )));
    }

    let resp_json: serde_json::Value = resp
        .json()
        .await
        .map_err(|e| AppError::Api(format!("Failed to parse Claude money-quote response: {e}")))?;

    let text = resp_json["content"][0]["text"]
        .as_str()
        .ok_or_else(|| AppError::Api("No text in Claude money-quote response".into()))?;

    let json_str = match serde_json::from_str::<MoneyQuoteResponse>(text.trim()) {
        Ok(r) => return Ok(validate_money_quote(r, CONFIDENCE_THRESHOLD)),
        Err(_) => extract_json_from_markdown(text)?,
    };

    let parsed: MoneyQuoteResponse = serde_json::from_str(&json_str)
        .map_err(|e| AppError::Api(format!("Malformed money-quote JSON: {e}")))?;

    Ok(validate_money_quote(parsed, CONFIDENCE_THRESHOLD))
}

#[derive(serde::Deserialize)]
struct MoneyQuoteResponse {
    quote: Option<String>,
    #[serde(default)]
    confidence: f32,
}

/// Apply confidence threshold + client-side 2–6 word validation.
/// Returns the quote only if both checks pass. Logs the confidence
/// value so we can tune the threshold from production data.
fn validate_money_quote(resp: MoneyQuoteResponse, threshold: f32) -> Option<String> {
    log::debug!(
        "money-quote LLM result — confidence: {:.2}, quote: {:?}",
        resp.confidence,
        resp.quote,
    );
    if resp.confidence < threshold {
        return None;
    }
    resp.quote.filter(|q| {
        let wc = q.split_whitespace().count();
        wc >= 2 && wc <= 6
    })
}

// ═══════════════════════════════════════════════════════════════════
//  JSON extraction helper (Phase 12 Wave 2)
// ═══════════════════════════════════════════════════════════════════

/// Strip common LLM wrappings around a JSON response and return the raw
/// JSON string. Tries (in order):
///
/// 1. ```` ```json ... ``` ```` — markdown code fence with language tag
/// 2. ```` ``` ... ``` ```` — generic markdown code fence
/// 3. First `{` through last `}` — slice out embedded JSON
///
/// Returns `Err` only if no balanced braces found at all.
///
/// This is tolerant on purpose — LLMs are inconsistent about emitting
/// structured output. For stricter guarantees we'd switch to Anthropic's
/// tool-use API; that's a larger migration deferred past Wave 2.
pub(crate) fn extract_json_from_markdown(text: &str) -> Result<String, AppError> {
    let trimmed = text.trim();

    // Layer 1: ```json ... ```
    if let Some(rest) = trimmed.strip_prefix("```json") {
        if let Some(inner) = rest.strip_suffix("```") {
            return Ok(inner.trim().to_string());
        }
    }

    // Layer 2: ``` ... ```
    if let Some(rest) = trimmed.strip_prefix("```") {
        if let Some(inner) = rest.strip_suffix("```") {
            return Ok(inner.trim().to_string());
        }
    }

    // Layer 3: first `{` to last `}`
    let start = trimmed.find('{')
        .ok_or_else(|| AppError::Api("No JSON object in response".into()))?;
    let end = trimmed.rfind('}')
        .ok_or_else(|| AppError::Api("No JSON closing brace in response".into()))?;
    if end <= start {
        return Err(AppError::Api("Unbalanced braces in response".into()));
    }
    Ok(trimmed[start..=end].to_string())
}

