        let horror = generate_from_parts(
            &["jumpscare".into(), "ambush".into()], None, "", 60.0, 0.8, 0.3, 0.7, 0,
        );

        // DirectQuote should differ (FPS: "no shot—" vs Horror: "oh god—")
